-- Redgum Shire Council: own multi-site demo assessment (generated).
-- Safe to run once; ON CONFLICT DO NOTHING makes re-runs no-ops.
do $$
declare v_org uuid; v_user uuid; v_site uuid;
begin
  select id into v_org from organisations where name = 'Redgum Shire Council' order by created_at limit 1;
  if v_org is null then select id into v_org from organisations where name ilike '%redgum%shire%' order by created_at limit 1; end if;
  if v_org is null then select id into v_org from organisations where name ilike '%redgum%' order by created_at limit 1; end if;
  if v_org is null then raise exception 'Redgum council org not found'; end if;
  select user_id into v_user from organisation_memberships where organisation_id = v_org and status = 'active' order by created_at limit 1;
  update organisations set jurisdiction = 'AU-SA' where id = v_org;

  -- ===== Central Library =====
  select id into v_site from sites where organisation_id = v_org and name = 'Central Library';
  values ('seed-redgum-central-library','1.1','1.1','completed','mixed','{"doingWell":["Where would it be easiest to start sharing accessibility information?","Does your physical access information include specific details that help customers plan?","Does your ''what to expect'' information describe the sensory and social environment?"],"priorityActions":[{"questionId":"1.1-F-1","questionText":"Do you have accessibility information available for customers before they visit?","action":"Create and publish accessibility information for customers before they visit. Include physical access details, sensory environment descriptions, and available supports. This is a key expectation under the DDA 1992.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.1-D-1b","questionText":"How easy is it to find your accessibility information from your homepage?","action":"Make your accessibility information findable within two clicks from your homepage. Add a prominent link in your main navigation, footer, or header. Avoid burying it under generic headings.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.1-F-3B","questionText":"How confident are you that this information is accurate and up to date?","action":"Establish a process to verify the accuracy of your accessibility information. Conduct a physical walkthrough of your venue comparing published details against actual conditions.","priority":"medium","timeframe":"30-90 days"},{"questionId":"1.1-D-10","questionText":"Do you clearly state limitations or barriers that still exist?","action":"Clearly state any known barriers or limitations on your accessibility page. Customers with disability prefer honest information about what is not accessible so they can plan accordingly, rather than discovering barriers on arrival.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["What''s currently a barrier for you to share accessibility information?","What types of accessibility information do you currently share?","Has your accessibility information been checked against any of these sources?"],"professionalReview":[]}'::jsonb,now() - interval '60 days',now() - interval '58 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','1.2','1.2','completed','mixed','{"doingWell":["When using the keyboard, can you always see which element is currently focused?","Do images on your website have alt text or image descriptions?","How consistently is alt text added to images?"],"priorityActions":[{"questionId":"1.2-1-1","questionText":"Can all website content be accessed using only a keyboard (no mouse required)?","action":"Test all interactive elements (menus, forms, modals, carousels) using only the Tab, Enter, and Arrow keys and fix any that cannot be reached or activated.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.2-1-4","questionText":"Can users resize text or zoom the page without losing content or functionality?","action":"Test your website at 200% browser zoom and fix any content that overflows, overlaps, becomes hidden, or loses functionality per WCAG 2.2 SC 1.4.4.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.2-1-6a","questionText":"Do your videos have captions?","action":"Add synchronised captions to all video content, using accurate, properly timed captions that include speaker identification and relevant sound effects per WCAG 2.2 SC 1.2.2.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Where does keyboard access break down?","Has your website contrast been formally measured or audited?"],"professionalReview":[]}'::jsonb,now() - interval '59 days',now() - interval '57 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','2.1','2.1','completed','strong','{"doingWell":["Are accessible parking spaces located close to the main entrance?","Is there a drop-off zone near the entrance for customers who need it?","Is the drop-off zone level and easy to access from the footpath?"],"priorityActions":[{"questionId":"2.1-F-1","questionText":"Do you have designated accessible parking spaces?","action":"Provide designated accessible parking spaces. Under the Premises Standards and AS/NZS 2890.6, at least one accessible space is required. Each space must be min 2400mm wide with a 2400mm shared area (or 3200mm for a single space) and 5400mm long.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-D-9c","questionText":"If parking requires payment, is the payment method accessible?","action":"Ensure parking payment is accessible. Options include contactless tap-and-go, a parking app with screen reader support, or a meter at accessible height (900-1100mm) with large buttons and high-contrast display. Avoid touch-screen-only meters without alternatives.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '58 days',now() - interval '56 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','2.2','2.2','completed','mixed','{"doingWell":["What does your main entrance have? (select all that apply)","Do the stair or step edges have contrasting nosing strips so each step is clearly visible?","Are the stair or step risers enclosed (no open gaps between steps)?"],"priorityActions":[{"questionId":"2.2-D-23","questionText":"If there are stairs or steps at the entrance, do they have handrails or grab rails on both sides?","action":"Install handrails on both sides of entrance stairs. Handrails must be continuous, 865-1000mm above the stair nosing, extend 300mm beyond the top and bottom treads, and have a graspable circular profile of 30-50mm diameter per AS 1428.1 Cl 11.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.2-D-28","questionText":"Does the ramp feel too steep for someone using a wheelchair or walking frame?","action":"Regrade or rebuild the ramp to comply with AS 1428.1 Cl 10: max gradient 1:14 for ramps up to 9m, 1:8 for kerb ramps. Provide level landings (min 1200mm long) at the top, bottom, and at max 9m intervals. Consider 1:20 or gentler for best practice.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.2-D-33","questionText":"Is there an accessible alternative (lift, ramp) for people who cannot use the escalator?","action":"Provide an accessible alternative (lift or ramp) adjacent to or clearly signed from the escalator. Under the Premises Standards, where an escalator is the primary means of access, a step-free alternative must be available.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Can the entrance lift be used independently without staff assistance?","Is there enough clear, level space in front of the entrance door for someone to stop and open it comfortably?"],"professionalReview":[]}'::jsonb,now() - interval '57 days',now() - interval '55 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','3.1','3.1','completed','mixed','{"doingWell":["Which of these seating options does your venue currently offer?","Is there space for wheelchair users alongside seated companions?","Are tables and counters at accessible heights for wheelchair users?"],"priorityActions":[{"questionId":"3.1-1-1","questionText":"Is there a variety of seating options (with arms, without arms, different heights)?","action":"Provide seating with different arm, height, and depth options so people with varying mobility, size, and support needs can find comfortable seating.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.1-D-10","questionText":"Is there an accessible writing surface available where customers need to complete forms or paperwork?","action":"Provide an accessible writing surface at locations where forms or paperwork are completed. Include a table or counter at 750-830mm height with minimum 800mm knee clearance and clear floor space for a wheelchair.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Which types of accessible seating does your venue offer in fixed seating areas?","Is rest seating available throughout your venue, including along walking routes, near high traffic areas, and at points of interest?","In fixed seating areas, do wheelchair spaces provide equivalent sightlines to other patrons?"],"professionalReview":[]}'::jsonb,now() - interval '56 days',now() - interval '54 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values (v_org,v_site,'3.1','3.1','seed-run-redgum-central-library-3.1-r1','{"type":"general","name":"Initial assessment (2026)"}'::jsonb,'completed', now() - interval '210 days', now() - interval '208 days','needs-work','{"doingWell":["Is there a variety of seating options (with arms, without arms, different heights)?","Which of these seating options does your venue currently offer?","Is there a lowered service counter or an alternative service point?"],"priorityActions":[{"questionId":"3.1-1-2","questionText":"Is there space for wheelchair users alongside seated companions?","action":"Designate clear wheelchair spaces (minimum 800mm x 1300mm per AS 1428.1) adjacent to standard seating so wheelchair users can sit alongside companions.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.1-1-3","questionText":"Are tables and counters at accessible heights for wheelchair users?","action":"Provide tables and counters with at least 750mm clearance underneath and a surface height no higher than 850mm so wheelchair users can approach and use them comfortably.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.1-1-4","questionText":"Can furniture be rearranged to accommodate different needs?","action":"Replace or supplement fixed furniture with movable options so staff can rearrange layouts for wheelchair users, mobility aid users, or service animals.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.1-D-2","questionText":"Are aisles and pathways between furniture wide enough throughout the space?","action":"Rearrange furniture to achieve minimum 1000mm clear width between obstacles, with 1200mm preferred and 1800mm at passing points, per AS 1428.1:2021 Clause 7.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Which types of accessible seating does your venue offer in fixed seating areas?"],"professionalReview":[]}'::jsonb,'[{"questionId":"3.1-1-1","answer":"yes","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-1","multiSelectValues":["back-support"],"timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-1-2","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-1-3","answer":"partially","partialDescription":"Designated accessible parking exists but line-marking has faded.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-1-4","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-2","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-3","multiSelectValues":["yes-lowered"],"timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-4","multiSelectValues":["eaa","eas","extra-width"],"timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-5","multiSelectValues":["limited"],"timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-6","answer":"yes","notes":"Verified with the venue coordinator.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-7","multiSelectValues":["indoor-only"],"timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-8","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-9","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-10","multiSelectValues":["yes-desk"],"timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-12","multiSelectValues":["limited"],"timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"3.1-D-13","multiSelectValues":["phone-only"],"timestamp":"2026-01-15T00:00:00.000Z"}]'::jsonb,v_user)
  on conflict (run_id) do nothing;
  values ('seed-redgum-central-library','3.5','3.5','completed','strong','{"doingWell":["Is signage clear, with good contrast and readable font sizes?","Are signs placed at consistent heights and locations?","Are accessible facilities (toilets, lifts) clearly signed?"],"priorityActions":[{"questionId":"3.5-D-3","questionText":"Is there directional signage at key decision points throughout the venue?","action":"Install directional signage at every point where a visitor needs to make a navigation decision, including corridor intersections, floor landings, and major room entries. Include arrows, distances, and key facility locations (toilets, exits, lifts) per AS 1428.1:2021.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.5-D-4","questionText":"Is there a map, floor plan, or directory showing the layout and key facilities?","action":"Create an accessible map or directory showing the venue layout including accessible toilets, lifts, exits, quiet spaces, hearing loop locations, and accessible parking. Provide in large print, digital, and tactile formats at the entrance.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '55 days',now() - interval '53 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','4.1','4.1','completed','strong','{"doingWell":["Do you offer alternatives to phone calls for customers who cannot or prefer not to use voice telephone?","Are your staff trained to receive calls via the National Relay Service (NRS)?","Do you capture and use customer communication preferences (preferred contact method, format needs)?"],"priorityActions":[{"questionId":"4.1-PC-4","questionText":"Do non-phone enquiries (email, text, chat) receive responses within the same timeframe as phone calls?","action":"Set and enforce equivalent service-level agreements for non-phone channels. If phone calls are answered within 2 minutes, email and chat should receive responses within the same window.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.1-PC-9","questionText":"Can customers provide feedback or complaints through multiple accessible channels (not just an online form)?","action":"Offer at least three feedback channels (e.g., phone, email, in-person, mail, SMS). Ensure at least one does not require internet access and at least one does not require verbal communication.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Where are customer communication preferences captured in your systems?","What training have staff received on communicating with people who have speech differences?"],"professionalReview":[]}'::jsonb,now() - interval '54 days',now() - interval '52 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','4.2','4.2','completed','mixed','{"doingWell":["Do staff know how to welcome and assist customers with assistance animals?","Do you have a process for customers to request assistance before arriving?","Are staff trained in various communication strategies?"],"priorityActions":[{"questionId":"4.2-F-1","questionText":"Have staff received disability awareness or inclusion training?","action":"Implement disability awareness and inclusion training for all customer-facing staff. Source training that includes lived-experience perspectives and practical scenario-based exercises, not just online modules.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-F-3","questionText":"Do staff feel confident communicating with customers who have different needs?","action":"Provide practical communication training covering interactions with people who are Deaf, blind, have intellectual disabilities, use wheelchairs, or have speech differences. Include role-play exercises.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-F-6","questionText":"Do staff know where accessible facilities are located to direct customers?","action":"Ensure all staff know the location of accessible toilets, lifts, hearing loops, quiet spaces, accessible parking, and any other accessible facilities. Include this in onboarding and display a staff reference map.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-D-16","questionText":"Do staff know how to assist customers during an emergency evacuation?","action":"Ensure staff are aware of your venue''s accessible evacuation procedures, including where refuge areas are located and how to assist customers with different needs. Detailed evacuation planning is covered in module 4.4.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true}],"areasToExplore":["Do staff know how to communicate with customers who are Deaf or hard of hearing?"],"professionalReview":[]}'::jsonb,now() - interval '53 days',now() - interval '51 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','4.3','4.3','completed','mixed','{"doingWell":["Are payment terminals positioned at accessible heights?","Can staff bring payment terminals to customers if needed?","Is your online booking system accessible?"],"priorityActions":[{"questionId":"4.3-1-1","questionText":"Can customers easily modify bookings if their needs change?","action":"Enable flexible booking modifications (date, time, accessibility requirements) through all booking channels and ensure the process is clearly communicated to customers.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.3-1-4","questionText":"Is there flexibility in cancellation policies for disability-related changes?","action":"Introduce flexible cancellation and modification terms for disability-related changes (e.g., health flare-ups, carer unavailability) and communicate this policy clearly during booking.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Can customers specify accessibility requirements during the booking process?","What payment methods do you accept?","Can customers book accessible spaces or equipment in advance?"],"professionalReview":[]}'::jsonb,now() - interval '52 days',now() - interval '50 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','4.5','4.5','completed','mixed','{"doingWell":["Are your surveys and feedback forms accessible?","Do you regularly review and act on accessibility feedback?","Have you received and responded to accessibility-related reviews?"],"priorityActions":[{"questionId":"4.5-D-1","questionText":"Do you offer multiple ways for customers to provide feedback?","action":"Offer at least three feedback channels: online form, email, phone, in-person, and postal mail. Ensure at least one option does not require internet access and at least one does not require verbal communication.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.5-D-7","questionText":"Can customers provide feedback anonymously if they prefer?","action":"Offer at least one anonymous feedback channel. Options include an anonymous online form, a physical suggestion box, or a third-party feedback service. Ensure customers know the option exists.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.5-D-8","questionText":"Do you involve people with disabilities in reviewing or improving your services (e.g., advisory panel, co-design sessions, paid consultants)?","action":"Engage people with disabilities in reviewing and improving your services. Options include a paid advisory panel, co-design workshops, or commissioned reviews by disability consultants with lived experience. Ensure participants are compensated.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do you have a way for customers to provide feedback about accessibility?","Do you actively monitor and respond to online reviews?"],"professionalReview":[]}'::jsonb,now() - interval '51 days',now() - interval '49 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','4.4','4.4','completed','mixed','{"doingWell":["Do your emergency procedures include plans for people with disabilities?","Are emergency exits accessible to people with mobility aids?","Do you have Personal Emergency Evacuation Plans (PEEPs) for people who need them?"],"priorityActions":[{"questionId":"4.4-1-3","questionText":"Are there visual and audible alarms for emergencies?","action":"Install dual-mode alarm systems with both audible alarms and visual strobes (flashing lights) in all areas, including toilets and quiet spaces, per AS 1670.4 and Premises Standards.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"4.4-1-4","questionText":"Do staff know how to assist customers with different needs during an evacuation?","action":"Conduct disability-inclusive evacuation training for all staff, covering wheelchair assistance, guiding a person who is blind, communicating with Deaf people, and supporting people experiencing anxiety or confusion.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"4.4-D-8","questionText":"How often are evacuation drills conducted, and do they include disability scenarios?","action":"Conduct evacuation drills at least every six months that include disability scenarios: evacuating a wheelchair user, guiding a blind person, communicating with a Deaf visitor, and supporting a person with cognitive disability. Document outcomes and improve procedures based on findings.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true}],"areasToExplore":["How do you communicate with Deaf visitors during an emergency?","Can you communicate visitor disability needs to external emergency services when they arrive?"],"professionalReview":[]}'::jsonb,now() - interval '50 days',now() - interval '48 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','5.1','5.1','completed','mixed','{"doingWell":["Do you have a documented accessibility or disability inclusion policy?","Do you have a Disability Inclusion Action Plan (DIAP) or equivalent?","Does your organisation have a policy on assistance animals?"],"priorityActions":[{"questionId":"5.1-F-4","questionText":"Do you accept the Companion Card for carers or support people?","action":"Register as a Companion Card affiliate. The scheme ensures carers and support people attend free of charge, removing a significant financial barrier. Contact your state or territory Companion Card program to enrol.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.1-F-5","questionText":"Do you have accessible pricing or concession options?","action":"Introduce concession pricing for people with disability. Consider free or discounted entry for Companion Card holders, pensioners, and NDIS participants. Make pricing information clear and easy to find.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.1-D-8","questionText":"Do you track and report on accessibility improvements?","action":"Implement a system to track accessibility improvements over time. Record what changes have been made, when, and their impact. Report progress to leadership at least quarterly to maintain momentum and accountability.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.1-D-12","questionText":"Do you have a process for handling accessibility-related complaints?","action":"Establish a formal process for handling accessibility-related complaints. Include clear steps for logging, investigating, resolving, and following up. Ensure the process itself is accessible (multiple contact methods, accessible forms, plain language).","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '49 days',now() - interval '47 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','5.3','5.3','completed','mixed','{"doingWell":["Do staff know how to use accessibility features and equipment?","Is disability training refreshed regularly?","Do staff have access to resources about accessibility and disability?"],"priorityActions":[{"questionId":"5.3-F-2","questionText":"Is disability awareness included in staff onboarding?","action":"Add disability awareness to your staff onboarding program. Cover your legal obligations under the DDA 1992, your organisation''s accessibility policy, how to communicate respectfully, and where to find accessibility resources and support.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.3-D-11","questionText":"Do contractors, casuals, and agency staff receive disability awareness training?","action":"Extend disability awareness training to contractors, casuals, and agency staff. These workers often have the most customer contact and must deliver the same inclusive service. Include an abbreviated accessibility induction as a minimum for short-term staff.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do all customer-facing staff receive disability awareness training?","Do staff know who to contact if they need advice on accessibility?","Does training cover Auslan and communicating with Deaf people?"],"professionalReview":[]}'::jsonb,now() - interval '48 days',now() - interval '46 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','5.4','5.4','completed','strong','{"doingWell":["Do you consider accessibility when selecting suppliers and partners?","Do you include accessibility requirements in contracts and tenders?","Do you ask suppliers about their accessibility practices?"],"priorityActions":[{"questionId":"5.4-D-3","questionText":"Do you verify that delivered products and services meet accessibility requirements?","action":"Implement accessibility verification for all products and services delivered. Test digital products against WCAG 2.2 AA, inspect physical works against AS 1428.1, and include people with disability in user acceptance testing where possible.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.4-D-7","questionText":"Do you include accessibility expertise in procurement decision-making?","action":"Include people with accessibility expertise in procurement decision-making. This could be an internal accessibility specialist, an external consultant, or an advisory panel that includes people with disability. Their input improves specification quality and evaluation accuracy.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.4-D-9","questionText":"Do you require key partners to demonstrate their own accessibility commitment?","action":"Require key partners and suppliers to demonstrate their own accessibility commitments. Ask for their accessibility policy, DIAP, or evidence of accessibility accreditation. Shared commitment creates consistency across the customer experience.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.4-D-10","questionText":"Do you have social procurement targets for purchasing from disability enterprises?","action":"Set social procurement targets for purchasing from disability enterprises and disability-led businesses. Even a modest target (e.g., 3-5% of addressable spend) creates significant impact. Track and report progress against these targets.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '47 days',now() - interval '45 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-central-library','5.7','5.7','completed','mixed','{"doingWell":["Do your job descriptions separate inherent requirements (what the role must do) from nice-to-haves (preferred but not essential)?","Do you represent disability positively in your employer branding (careers page, photos, testimonials)?","Is there a named owner or governance group responsible for signing off on inherent requirements before a role is advertised?"],"priorityActions":[{"questionId":"5.7-PC-2","questionText":"Do your job ads use plain language and disclose the salary range?","action":"Rewrite ad templates in plain language. Commit to disclosing salary ranges on all ads. Test readability before posting.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.7-PC-3","questionText":"Do your job ads include a clear access statement inviting candidates to request adjustments, with a named contact?","action":"Add a named-contact access statement to every ad template. Offer multiple formats and contact methods. Make clear disclosure is not required.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"5.7-PC-4","questionText":"Do you advertise roles through disability-led networks and specialist employment services, not only mainstream job boards?","action":"Identify 1–2 DES providers or disability-led networks for your sector. Build ongoing relationships, not one-off posts.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.7-DD-3","questionText":"Do you offer job ads and application information in alternative formats (Easy Read, Auslan video, audio, plain text email)?","action":"Start with plain text email (free). Plan Easy Read and Auslan for high-volume or strategic roles.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Is your application process (ATS, forms, portals) accessible to screen readers and keyboard-only users?","Do you apply the same accessibility standards to volunteer, contractor, casual, and internship advertising as to permanent roles?","Are careers page, employer-brand video, and candidate testimonial content audited annually against WCAG 2.2 AA?"],"professionalReview":[]}'::jsonb,now() - interval '46 days',now() - interval '44 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;

  -- ===== Regional Art Gallery =====
  select id into v_site from sites where organisation_id = v_org and name = 'Regional Art Gallery';
  values ('seed-redgum-regional-art-gallery','1.1','1.1','completed','mixed','{"doingWell":["Do you have accessibility information available for customers before they visit?","Does your physical access information include specific details that help customers plan?","Does your ''what to expect'' information describe the sensory and social environment?"],"priorityActions":[{"questionId":"1.1-D-9","questionText":"Is your accessibility information consistent across all platforms?","action":"Audit all platforms where your accessibility information appears and ensure consistency. Discrepancies between your website, Google listing, social media, and third-party platforms create confusion and erode trust.","priority":"high","timeframe":"30-90 days"},{"questionId":"1.1-D-10","questionText":"Do you clearly state limitations or barriers that still exist?","action":"Clearly state any known barriers or limitations on your accessibility page. Customers with disability prefer honest information about what is not accessible so they can plan accordingly, rather than discovering barriers on arrival.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["What''s currently a barrier for you to share accessibility information?","Where would it be easiest to start sharing accessibility information?","What types of accessibility information do you currently share?"],"professionalReview":[]}'::jsonb,now() - interval '45 days',now() - interval '43 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-regional-art-gallery','2.1','2.1','completed','strong','{"doingWell":["Do you have designated accessible parking spaces?","Are accessible parking spaces located close to the main entrance?","Is there a drop-off zone near the entrance for customers who need it?"],"priorityActions":[{"questionId":"2.1-F-3a","questionText":"Is the drop-off zone level and easy to access from the footpath?","action":"Regrade or modify the drop-off zone to provide a firm, level surface flush with the adjacent footpath. Install a kerb ramp or dropped kerb per AS 1428.1 Cl 10 if there is a level change between the roadway and the path.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-D-9a","questionText":"Is the surface of accessible parking spaces firm and slip-resistant?","action":"Resurface accessible parking spaces with a firm, slip-resistant material (e.g., sealed concrete or asphalt). Gravel, loose pebbles, and worn bitumen with potholes do not meet the requirements of AS 1428.1 for a continuous accessible path.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-D-13","questionText":"Are accessible parking spaces clearly marked with both ground markings and vertical signage?","action":"Mark accessible parking spaces with both ground-level ISA symbols (painted on the bay surface) and vertical signage (a sign post or wall-mounted sign at min 1200mm height). Both are required under AS/NZS 2890.6 Cl 2.4.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Is there directional signage on the road approach directing visitors to accessible parking?"],"professionalReview":[]}'::jsonb,now() - interval '44 days',now() - interval '42 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-regional-art-gallery','2.2','2.2','completed','strong','{"doingWell":["What does your main entrance have? (select all that apply)","If there are stairs or steps at the entrance, do they have handrails or grab rails on both sides?","Are the stair or step risers enclosed (no open gaps between steps)?"],"priorityActions":[{"questionId":"2.2-D-24","questionText":"Do the stair or step edges have contrasting nosing strips so each step is clearly visible?","action":"Apply contrasting nosing strips to every step edge on entrance stairs. Strips must provide min 30% luminance contrast with both the tread and the riser, extend the full width of the stair, and be 50-75mm on the tread and 30mm on the riser per AS 1428.1 Cl 11.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.2-D-28","questionText":"Does the ramp feel too steep for someone using a wheelchair or walking frame?","action":"Regrade or rebuild the ramp to comply with AS 1428.1 Cl 10: max gradient 1:14 for ramps up to 9m, 1:8 for kerb ramps. Provide level landings (min 1200mm long) at the top, bottom, and at max 9m intervals. Consider 1:20 or gentler for best practice.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Can the entrance lift be used independently without staff assistance?"],"professionalReview":[]}'::jsonb,now() - interval '43 days',now() - interval '41 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-regional-art-gallery','3.1','3.1','completed','strong','{"doingWell":["Which of these seating options does your venue currently offer?","Is there space for wheelchair users alongside seated companions?","Can furniture be rearranged to accommodate different needs?"],"priorityActions":[{"questionId":"3.1-1-3","questionText":"Are tables and counters at accessible heights for wheelchair users?","action":"Provide tables and counters with at least 750mm clearance underneath and a surface height no higher than 850mm so wheelchair users can approach and use them comfortably.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.1-D-3","questionText":"Is there a lowered service counter or an alternative service point?","action":"Install a lowered section of the service counter at 830mm maximum height with 800mm minimum knee clearance depth, or establish a clearly signed alternative service point accessible to wheelchair users, per AS 1428.1:2021.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Is there a variety of seating options (with arms, without arms, different heights)?"],"professionalReview":[]}'::jsonb,now() - interval '42 days',now() - interval '40 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-regional-art-gallery','3.3','3.3','completed','mixed','{"doingWell":["Are there quiet or reset spaces available for people who need a sensory break?","Are there any flashing lights or sudden loud noises that could affect some visitors?","Can indoor temperature be managed or regulated for different needs?"],"priorityActions":[{"questionId":"3.3-1-1","questionText":"Does lighting support comfortable navigation and sensory regulation?","action":"Assess lighting levels throughout the venue and address flickering, harsh fluorescent lights, and dark spots that affect people with low vision, migraines, or sensory sensitivities.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.3-1-3","questionText":"Is background noise at a level that allows conversation?","action":"Measure noise levels in key areas and reduce background noise through acoustic treatment, music volume limits, or designated quieter zones to support hearing aid users and people who lip-read.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.3-D-2","questionText":"Is lighting even and consistent at key service and communication areas (reception, counters, information points)?","action":"Improve lighting at service counters, reception, and information points to a minimum 300 lux evenly distributed, avoiding shadows on faces. Good lighting at these points is essential for lipreading and clear communication.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.3-D-5","questionText":"Is background music volume adjustable or able to be managed?","action":"Install zone controls for background music so volume can be reduced or muted in service areas. Background music above 50dB significantly impairs communication for hearing aid users and people who lipread.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Can lighting be adjusted or dimmed in any areas?","Where are your hearing loops installed?"],"professionalReview":[]}'::jsonb,now() - interval '41 days',now() - interval '39 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-regional-art-gallery','3.5','3.5','completed','strong','{"doingWell":["Is signage clear, with good contrast and readable font sizes?","Are signs placed at consistent heights and locations?","Are accessible facilities (toilets, lifts) clearly signed?"],"priorityActions":[{"questionId":"3.5-D-5","questionText":"Is there clear signage on the approach to your venue and at the entrance?","action":"Install clear, high-contrast signage on the approach to your venue and at the entrance. Include the venue name, entrance location, and international accessibility symbols where relevant. Ensure signs are visible from the street and car park.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '40 days',now() - interval '38 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-regional-art-gallery','4.2','4.2','completed','strong','{"doingWell":["Have staff received disability awareness or inclusion training?","Do staff know how to welcome and assist customers with assistance animals?","Do staff feel confident communicating with customers who have different needs?"],"priorityActions":[{"questionId":"4.2-D-11","questionText":"Is pen and paper available for written communication if needed?","action":"Keep pen and paper (or a whiteboard and marker) at all customer service points for written communication with customers who are Deaf, have speech disabilities, or prefer written exchange.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '39 days',now() - interval '37 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-regional-art-gallery','4.1','4.1','completed','mixed','{"doingWell":["Do you offer alternatives to phone calls for customers who cannot or prefer not to use voice telephone?","Are your staff trained to receive calls via the National Relay Service (NRS)?","Do you capture and use customer communication preferences (preferred contact method, format needs)?"],"priorityActions":[{"questionId":"4.1-PC-4","questionText":"Do non-phone enquiries (email, text, chat) receive responses within the same timeframe as phone calls?","action":"Set and enforce equivalent service-level agreements for non-phone channels. If phone calls are answered within 2 minutes, email and chat should receive responses within the same window.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.1-PC-9","questionText":"Can customers provide feedback or complaints through multiple accessible channels (not just an online form)?","action":"Offer at least three feedback channels (e.g., phone, email, in-person, mail, SMS). Ensure at least one does not require internet access and at least one does not require verbal communication.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.1-PC-10","questionText":"Do you respond to customers in their preferred format, even when it requires extra effort?","action":"Establish a process for responding to customers in their stated preferred format (e.g., large print letter, email instead of phone, Easy Read). Document preferences and ensure all staff follow them.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.1-DD-1b","questionText":"Are phone alternatives as prominently displayed as your phone number on your website and materials?","action":"Display non-phone contact options (email, chat, SMS) with equal prominence to your phone number on your website, Google Business listing, and printed materials. Avoid burying alternatives in sub-pages.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Where are customer communication preferences captured in your systems?","What training have staff received on communicating with people who have speech differences?"],"professionalReview":[]}'::jsonb,now() - interval '38 days',now() - interval '36 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-regional-art-gallery','4.4','4.4','completed','mixed','{"doingWell":["Do your emergency procedures include plans for people with disabilities?","Are emergency exits accessible to people with mobility aids?","Do staff know how to assist customers with different needs during an evacuation?"],"priorityActions":[{"questionId":"4.4-1-3","questionText":"Are there visual and audible alarms for emergencies?","action":"Install dual-mode alarm systems with both audible alarms and visual strobes (flashing lights) in all areas, including toilets and quiet spaces, per AS 1670.4 and Premises Standards.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true}],"areasToExplore":["How do you communicate with Deaf visitors during an emergency?"],"professionalReview":[]}'::jsonb,now() - interval '37 days',now() - interval '35 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-regional-art-gallery','4.6','4.6','completed','strong','{"doingWell":["Are your marketing emails and newsletters accessible?","Can customers easily manage their communication preferences?","Are your promotional offers and discounts accessible to everyone?"],"priorityActions":[{"questionId":"4.6-D-1","questionText":"Do you offer SMS or text alternatives to email communications?","action":"Offer SMS or text message alternatives to email for key communications: appointment reminders, booking confirmations, service updates, and promotional offers. Allow customers to opt in to SMS as their preferred channel.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.6-D-5","questionText":"If you offer live chat or online messaging, is it accessible?","action":"Audit your live chat or online messaging for WCAG 2.2 AA compliance: keyboard navigable, screen reader compatible, adequate timeout warnings, works with browser zoom, and does not rely on colour alone for status indicators.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.6-D-7","questionText":"Do you notify customers when you make accessibility improvements?","action":"Communicate accessibility improvements to customers: update your website, send targeted notifications to customers who previously flagged related needs, post on social media, and include in newsletters.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.6-D-9","questionText":"Do you include Auslan (Australian Sign Language) content in any of your communications?","action":"Consider incorporating Auslan (Australian Sign Language) content into your communications. Start with key information: welcome messages, safety information, or service explanations. Engage qualified Auslan interpreters, not amateur signers.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '36 days',now() - interval '34 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-regional-art-gallery','5.5','5.5','completed','strong','{"doingWell":["Do you set accessibility improvement goals?","Do you report on accessibility progress to leadership or stakeholders?","Do you conduct regular accessibility audits?"],"priorityActions":[{"questionId":"5.5-F-1","questionText":"Do you regularly review your accessibility performance?","action":"Establish a regular cadence for reviewing accessibility performance. At minimum, conduct a quarterly review covering complaint trends, DIAP progress, audit findings, and customer feedback. Use the results to adjust priorities and allocate resources.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.5-D-6","questionText":"Have you had external accessibility audits or reviews?","action":"Commission an external accessibility audit or review. Independent assessment by qualified access consultants provides credible findings, identifies blind spots, and can benchmark your performance. Budget for physical, digital, and service delivery audits.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do you learn from accessibility complaints and incidents to prevent recurrence?"],"professionalReview":[]}'::jsonb,now() - interval '35 days',now() - interval '33 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-regional-art-gallery','5.7','5.7','completed','mixed','{"doingWell":["Do your job descriptions separate inherent requirements (what the role must do) from nice-to-haves (preferred but not essential)?","Do you advertise roles through disability-led networks and specialist employment services, not only mainstream job boards?","Is your application process (ATS, forms, portals) accessible to screen readers and keyboard-only users?"],"priorityActions":[{"questionId":"5.7-PC-6","questionText":"Do you represent disability positively in your employer branding (careers page, photos, testimonials)?","action":"Plan a careers content update. Invite Disabled staff to contribute (paid). Replace generic DEI statements with visible, authentic representation.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.7-DD-6","questionText":"Do you apply the same accessibility standards to volunteer, contractor, casual, and internship advertising as to permanent roles?","action":"Extend templates and standards to volunteer, casual, contractor, and intern advertising.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.7-DD-8","questionText":"Are careers page, employer-brand video, and candidate testimonial content audited annually against WCAG 2.2 AA?","action":"Add careers content to the annual accessibility audit scope. Audit ATS portal specifically.","priority":"medium","timeframe":"30-90 days","complianceLevel":"wcag-aa"},{"questionId":"5.7-DD-9","questionText":"Do you have formal pipeline partnerships (traineeships, paid internships, graduate programs) with disability-led or sector-specific organisations?","action":"Identify one partner. Scope a small pilot (2-3 placements). Measure and scale.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do your job ads use plain language and disclose the salary range?","Do your job ads include a clear access statement inviting candidates to request adjustments, with a named contact?","Do you measure applicant diversity (disclosure rate, shortlist, offer) against labour market benchmarks and review annually?"],"professionalReview":[]}'::jsonb,now() - interval '34 days',now() - interval '32 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;

  -- ===== Visitor Information Centre =====
  select id into v_site from sites where organisation_id = v_org and name = 'Visitor Information Centre';
  values ('seed-redgum-visitor-information-centre','1.1','1.1','completed','mixed','{"doingWell":["Do you have accessibility information available for customers before they visit?","Where is your accessibility information published?","When was your accessibility information last reviewed or updated?"],"priorityActions":[{"questionId":"1.1-D-12","questionText":"Who is responsible for maintaining your accessibility information?","action":"Assign a specific person or role as responsible for maintaining your accessibility information. Without clear ownership, information becomes outdated and inaccurate.","priority":"medium","timeframe":"30-90 days"}],"areasToExplore":["What''s currently a barrier for you to share accessibility information?","Where would it be easiest to start sharing accessibility information?","What types of accessibility information do you currently share?"],"professionalReview":[]}'::jsonb,now() - interval '33 days',now() - interval '31 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-visitor-information-centre','1.4','1.4','completed','mixed','{"doingWell":["Do your videos have captions or subtitles?","Do your captions include speaker identification and sound descriptions?","Are your captions accurately synchronised with the audio?"],"priorityActions":[{"questionId":"1.4-PC-3","questionText":"Do you include alt text or image descriptions when posting images on social media?","action":"Add descriptive alt text or image descriptions to all images posted on social media. Most platforms (Instagram, Facebook, X/Twitter, LinkedIn) support alt text natively. Describe the content and context of the image, not just \"photo\" or \"image.\"","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.4-PC-4","questionText":"Can users control video playback using keyboard, screen readers, or other assistive technology?","action":"Ensure all video players on your website support keyboard controls and are compatible with screen readers and other assistive technology, per WCAG 2.2 Success Criterion 2.1.1 (Keyboard). Users must be able to play, pause, adjust volume, and toggle captions without a mouse.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.4-DD-4b","questionText":"Do videos autoplay on your website or social media?","action":"Disable autoplay for videos on your website, or ensure autoplaying videos are muted by default with easy-to-find pause/stop controls, per WCAG 2.2 Success Criteria 1.4.2 (Audio Control) and 2.2.2 (Pause, Stop, Hide). Autoplaying video with sound is disorienting and inaccessible.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.4-PC-5","questionText":"Do you provide content warnings for videos or posts that may affect some viewers?","action":"Provide content warnings for videos or posts that may affect some viewers, including flashing/strobing, loud sounds, distressing imagery, or content depicting medical procedures. Place warnings before the content begins.","priority":"medium","timeframe":"30-90 days"}],"areasToExplore":["Do your videos include audio descriptions for important visual content?","Do you add alt text or image descriptions to each image in carousel or multi-image posts?","If you create live video content (streams, webinars, live social posts), do you consider accessibility?"],"professionalReview":[]}'::jsonb,now() - interval '32 days',now() - interval '30 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-visitor-information-centre','1.5','1.5','completed','strong','{"doingWell":["Do you use respectful, person-centred language when referring to people with disability?","Is your accessibility language welcoming and customer-focused?","Do you actively communicate your commitment to accessibility (not just list features)?"],"priorityActions":[{"questionId":"1.5-PC-4","questionText":"Is accessibility information easy to find on your website (not buried or hidden)?","action":"Make your accessibility information easy to find on your website. Add it to your main navigation or footer menu with a clear label such as \"Accessibility\" or \"Access Information.\" Do not bury it under unrelated sections.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.5-PC-5","questionText":"Does your accessibility information cover practical details customers need to plan their visit?","action":"Expand your accessibility information to cover practical details customers need to plan their visit, including physical access, parking, transport, toilets, sensory environment, available supports, and what to expect on arrival.","priority":"high","timeframe":"30-90 days"},{"questionId":"1.5-DD-1a","questionText":"Have you tested your website content for readability level?","action":"Test your website content for readability level using tools such as the Flesch-Kincaid readability score or Hemingway Editor. Aim for a reading level of Year 8 or below for general public content.","priority":"medium","timeframe":"30-90 days"}],"areasToExplore":["How do you communicate your accessibility commitment to customers?"],"professionalReview":[]}'::jsonb,now() - interval '31 days',now() - interval '29 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-visitor-information-centre','2.1','2.1','completed','mixed','{"doingWell":["Do you have designated accessible parking spaces?","Is the drop-off zone level and easy to access from the footpath?","Is the path to your entrance wide enough for people using mobility aids, walking with companions or using service animals (at least 1 metre wide)?"],"priorityActions":[{"questionId":"2.1-F-2","questionText":"Are accessible parking spaces located close to the main entrance?","action":"Relocate or designate accessible parking spaces as close as practicable to the main entrance. AS/NZS 2890.6 recommends the shortest practicable route. Prioritise spaces nearest to the accessible entry path.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-3","questionText":"Is there a drop-off zone near the entrance for customers who need it?","action":"Establish a designated drop-off zone near the main entrance. Mark it clearly with signage and ensure it connects to the accessible path of travel. Consider a minimum 6000mm length to accommodate larger accessible vehicles.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.1-F-4","questionText":"Is the path from accessible parking to the entrance smooth and level?","action":"Resurface or regrade the path from accessible parking to the entrance to provide a continuous accessible path of travel. The surface must be firm, slip-resistant, and free of trip hazards per AS 1428.1 Cl 7. Maximum crossfall is 1:40.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.1-F-6","questionText":"Is there directional signage on the road approach directing visitors to accessible parking?","action":"Install directional signage on the road approach indicating the location of accessible parking. Use the International Symbol of Access (ISA) with a directional arrow, visible from the vehicle approach. Position signs at each decision point.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '30 days',now() - interval '28 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-visitor-information-centre','4.1','4.1','completed','mixed','{"doingWell":["Do non-phone enquiries (email, text, chat) receive responses within the same timeframe as phone calls?","Can customers provide feedback or complaints through multiple accessible channels (not just an online form)?","Do you respond to customers in their preferred format, even when it requires extra effort?"],"priorityActions":[{"questionId":"4.1-PC-1","questionText":"Do you offer alternatives to phone calls for customers who cannot or prefer not to use voice telephone?","action":"Provide at least two non-phone contact options (e.g., email, live chat, SMS, online form). Under the DDA 1992, services must be accessible to people who cannot use voice telephone.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"4.1-PC-3","questionText":"Do you capture and use customer communication preferences (preferred contact method, format needs)?","action":"Add a communication preferences field to your customer records (preferred contact method, format needs such as large print or Easy Read). Ask at first contact and store for future use.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.1-PC-5","questionText":"Are staff trained to communicate patiently with people who have speech disabilities, strong accents, or use AAC devices?","action":"Provide staff training on communicating with people who have speech disabilities, strong accents, or who use AAC (Augmentative and Alternative Communication) devices. Include practical scenarios and allow extra time in interactions.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.1-PC-8","questionText":"Do you offer written confirmation or follow-up after important phone or in-person conversations?","action":"Offer written confirmation (email, SMS, or letter) after important phone or in-person conversations covering bookings, service changes, or access arrangements.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Are your staff trained to receive calls via the National Relay Service (NRS)?","Do staff know what AAC (Augmentative and Alternative Communication) devices are and how to interact with users?","Is there a quiet space available for communication with customers who need a calmer environment?"],"professionalReview":[]}'::jsonb,now() - interval '29 days',now() - interval '27 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-visitor-information-centre','4.2','4.2','completed','mixed','{"doingWell":["Do staff know how to welcome and assist customers with assistance animals?","Do staff feel confident communicating with customers who have different needs?","Do you have a process for customers to request assistance before arriving?"],"priorityActions":[{"questionId":"4.2-F-6","questionText":"Do staff know where accessible facilities are located to direct customers?","action":"Ensure all staff know the location of accessible toilets, lifts, hearing loops, quiet spaces, accessible parking, and any other accessible facilities. Include this in onboarding and display a staff reference map.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-D-11","questionText":"Is pen and paper available for written communication if needed?","action":"Keep pen and paper (or a whiteboard and marker) at all customer service points for written communication with customers who are Deaf, have speech disabilities, or prefer written exchange.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-D-13","questionText":"Is there a quiet space available for customers who become overwhelmed?","action":"Designate a quiet, low-stimulus space where customers who become overwhelmed can decompress. Ensure staff know where it is and can offer it proactively when a customer appears distressed.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Have staff received disability awareness or inclusion training?","Do staff know how to assist customers who may need extra time or have cognitive differences?","Do you have a documented policy on serving customers with disabilities?"],"professionalReview":[]}'::jsonb,now() - interval '28 days',now() - interval '26 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-visitor-information-centre','4.4','4.4','completed','mixed','{"doingWell":["Are there visual and audible alarms for emergencies?","Do staff know how to assist customers with different needs during an evacuation?","Do you have Personal Emergency Evacuation Plans (PEEPs) for people who need them?"],"priorityActions":[{"questionId":"4.4-1-1","questionText":"Do your emergency procedures include plans for people with disabilities?","action":"Update your emergency management plan to include specific procedures for evacuating people with mobility, sensory, cognitive, and psychosocial disabilities per DDA 1992 obligations.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true}],"areasToExplore":["Are emergency exits accessible to people with mobility aids?","How do you communicate with Deaf visitors during an emergency?","Are emergency procedures displayed in accessible formats?"],"professionalReview":[]}'::jsonb,now() - interval '27 days',now() - interval '25 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-visitor-information-centre','4.5','4.5','completed','strong','{"doingWell":["Are your surveys and feedback forms accessible?","Do you actively monitor and respond to online reviews?","Do you regularly review and act on accessibility feedback?"],"priorityActions":[{"questionId":"4.5-F-1","questionText":"Do you have a way for customers to provide feedback about accessibility?","action":"Create a way for customers to provide feedback specifically about accessibility. Include it in your general feedback channels but also offer a dedicated accessibility feedback option (email address, form, or phone line).","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.5-D-1","questionText":"Do you offer multiple ways for customers to provide feedback?","action":"Offer at least three feedback channels: online form, email, phone, in-person, and postal mail. Ensure at least one option does not require internet access and at least one does not require verbal communication.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do you communicate improvements made in response to accessibility feedback?"],"professionalReview":[]}'::jsonb,now() - interval '26 days',now() - interval '24 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-visitor-information-centre','5.4','5.4','completed','mixed','{"doingWell":["Do you consider accessibility when selecting suppliers and partners?","Do you include accessibility requirements in contracts and tenders?","Do you verify that delivered products and services meet accessibility requirements?"],"priorityActions":[{"questionId":"5.4-D-1","questionText":"Do you ask suppliers about their accessibility practices?","action":"Include accessibility questions in your supplier assessment process. Ask about their accessibility policy, WCAG compliance (for digital suppliers), physical accessibility of their premises, and whether they employ people with disability.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.4-D-2","questionText":"Do you prioritise suppliers with strong accessibility practices?","action":"Give preference to suppliers with strong accessibility practices where capability and price are comparable. This creates market incentive for suppliers to invest in accessibility and aligns your supply chain with your inclusion values.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.4-D-9","questionText":"Do you require key partners to demonstrate their own accessibility commitment?","action":"Require key partners and suppliers to demonstrate their own accessibility commitments. Ask for their accessibility policy, DIAP, or evidence of accessibility accreditation. Shared commitment creates consistency across the customer experience.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.4-D-10","questionText":"Do you have social procurement targets for purchasing from disability enterprises?","action":"Set social procurement targets for purchasing from disability enterprises and disability-led businesses. Even a modest target (e.g., 3-5% of addressable spend) creates significant impact. Track and report progress against these targets.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do you monitor that ongoing partners and suppliers maintain accessibility standards?"],"professionalReview":[]}'::jsonb,now() - interval '25 days',now() - interval '23 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-visitor-information-centre','5.7','5.7','completed','mixed','{"doingWell":["Do your job ads use plain language and disclose the salary range?","Do your job ads include a clear access statement inviting candidates to request adjustments, with a named contact?","Do you represent disability positively in your employer branding (careers page, photos, testimonials)?"],"priorityActions":[{"questionId":"5.7-PC-4","questionText":"Do you advertise roles through disability-led networks and specialist employment services, not only mainstream job boards?","action":"Identify 1–2 DES providers or disability-led networks for your sector. Build ongoing relationships, not one-off posts.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.7-DD-7","questionText":"Do you measure applicant diversity (disclosure rate, shortlist, offer) against labour market benchmarks and review annually?","action":"Pull ABS prevalence for your sector. Compare to your last 12 months of applicant data.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.7-DD-9","questionText":"Do you have formal pipeline partnerships (traineeships, paid internships, graduate programs) with disability-led or sector-specific organisations?","action":"Identify one partner. Scope a small pilot (2-3 placements). Measure and scale.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do your job descriptions separate inherent requirements (what the role must do) from nice-to-haves (preferred but not essential)?","Is your application process (ATS, forms, portals) accessible to screen readers and keyboard-only users?","Are roles routinely considered for part-time, job-share, or flexible arrangements before being advertised as full-time only?"],"professionalReview":[]}'::jsonb,now() - interval '24 days',now() - interval '22 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
