  -- ===== Aquatic & Leisure Centre =====
  select id into v_site from sites where organisation_id = v_org and name = 'Aquatic & Leisure Centre';
  values ('seed-redgum-aquatic-leisure-centre','2.1','2.1','completed','mixed','{"doingWell":["Is there a drop-off zone near the entrance for customers who need it?","Is the drop-off zone level and easy to access from the footpath?","Is there directional signage on the road approach directing visitors to accessible parking?"],"priorityActions":[{"questionId":"2.1-F-1","questionText":"Do you have designated accessible parking spaces?","action":"Provide designated accessible parking spaces. Under the Premises Standards and AS/NZS 2890.6, at least one accessible space is required. Each space must be min 2400mm wide with a 2400mm shared area (or 3200mm for a single space) and 5400mm long.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-2","questionText":"Are accessible parking spaces located close to the main entrance?","action":"Relocate or designate accessible parking spaces as close as practicable to the main entrance. AS/NZS 2890.6 recommends the shortest practicable route. Prioritise spaces nearest to the accessible entry path.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-4","questionText":"Is the path from accessible parking to the entrance smooth and level?","action":"Resurface or regrade the path from accessible parking to the entrance to provide a continuous accessible path of travel. The surface must be firm, slip-resistant, and free of trip hazards per AS 1428.1 Cl 7. Maximum crossfall is 1:40.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.1-F-5","questionText":"Is the path to your entrance wide enough for people using mobility aids, walking with companions or using service animals (at least 1 metre wide)?","action":"Widen the path to at least 1000mm clear width (1200mm preferred, 1800mm at passing points) per AS 1428.1 Cl 7. Remove any obstructions that narrow the effective width, including overhanging vegetation, bins, or signage.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '23 days',now() - interval '21 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values (v_org,v_site,'2.1','2.1','seed-run-redgum-aquatic-leisure-centre-2.1-r1','{"type":"general","name":"Initial assessment (2026)"}'::jsonb,'completed', now() - interval '210 days', now() - interval '208 days','needs-work','{"doingWell":["Is there a drop-off zone near the entrance for customers who need it?","Is the path to your entrance wide enough for people using mobility aids, walking with companions or using service animals (at least 1 metre wide)?","If parking requires payment, is the payment method accessible?"],"priorityActions":[{"questionId":"2.1-F-1","questionText":"Do you have designated accessible parking spaces?","action":"Provide designated accessible parking spaces. Under the Premises Standards and AS/NZS 2890.6, at least one accessible space is required. Each space must be min 2400mm wide with a 2400mm shared area (or 3200mm for a single space) and 5400mm long.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-2","questionText":"Are accessible parking spaces located close to the main entrance?","action":"Relocate or designate accessible parking spaces as close as practicable to the main entrance. AS/NZS 2890.6 recommends the shortest practicable route. Prioritise spaces nearest to the accessible entry path.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-3a","questionText":"Is the drop-off zone level and easy to access from the footpath?","action":"Regrade or modify the drop-off zone to provide a firm, level surface flush with the adjacent footpath. Install a kerb ramp or dropped kerb per AS 1428.1 Cl 10 if there is a level change between the roadway and the path.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-4","questionText":"Is the path from accessible parking to the entrance smooth and level?","action":"Resurface or regrade the path from accessible parking to the entrance to provide a continuous accessible path of travel. The surface must be firm, slip-resistant, and free of trip hazards per AS 1428.1 Cl 7. Maximum crossfall is 1:40.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true}],"areasToExplore":["If the accessible route differs from the main pedestrian path, is it clearly signed?"],"professionalReview":[]}'::jsonb,'[{"questionId":"2.1-F-1","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-2","answer":"partially","partialDescription":"Ramp at the main entrance but the side entrance still has a single step.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-3","answer":"yes","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-3a","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-4","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-5","answer":"yes","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-6","answer":"partially","partialDescription":"Accessible toilet available but the change table is not adult-sized.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-6a","answer":"partially","partialDescription":"Large-print materials available on request but not routinely offered.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-6b","answer":"unable-to-check","notes":"Not sure this has been checked since the last refurbishment.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-7","answer":"partially","partialDescription":"Accessibility information is on the website but scattered across a few pages rather than one place.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-8","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-D-9","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-D-9a","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-D-9c","answer":"yes","notes":"Confirmed on site during the March access walk-through.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-D-13","answer":"yes","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-D-10","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"}]'::jsonb,v_user)
  on conflict (run_id) do nothing;
  values ('seed-redgum-aquatic-leisure-centre','2.2','2.2','completed','mixed','{"doingWell":["What does your main entrance have? (select all that apply)","Are the stair or step risers enclosed (no open gaps between steps)?","If there is a ramp, does it have handrails on both sides?"],"priorityActions":[{"questionId":"2.2-D-23","questionText":"If there are stairs or steps at the entrance, do they have handrails or grab rails on both sides?","action":"Install handrails on both sides of entrance stairs. Handrails must be continuous, 865-1000mm above the stair nosing, extend 300mm beyond the top and bottom treads, and have a graspable circular profile of 30-50mm diameter per AS 1428.1 Cl 11.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.2-D-24","questionText":"Do the stair or step edges have contrasting nosing strips so each step is clearly visible?","action":"Apply contrasting nosing strips to every step edge on entrance stairs. Strips must provide min 30% luminance contrast with both the tread and the riser, extend the full width of the stair, and be 50-75mm on the tread and 30mm on the riser per AS 1428.1 Cl 11.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.2-D-26","questionText":"Are there tactile ground surface indicators (TGSIs) at the top and bottom of the stairs or steps?","action":"Install tactile ground surface indicators (TGSIs) at the top and bottom of entrance stairs. Warning TGSIs (truncated domes) must extend 600mm from the stair nosing across the full width, with min 30% luminance contrast, per AS 1428.4.1.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.2-D-29","questionText":"Are there tactile ground surface indicators (TGSIs) at the top and bottom of the ramp?","action":"Install warning TGSIs (truncated domes) at the top and bottom of the entrance ramp per AS 1428.4.1. TGSIs must extend 600mm from the ramp edge across the full width, with min 30% luminance contrast against the surrounding surface.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Is there enough clear, level space in front of the entrance door for someone to stop and open it comfortably?"],"professionalReview":[]}'::jsonb,now() - interval '22 days',now() - interval '20 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-aquatic-leisure-centre','2.3','2.3','completed','mixed','{"doingWell":["Does your venue have any internal level changes? Select all that apply:","Is there enough space for two people to pass each other, or for a wheelchair to turn around?","Is there enough clear space on both sides of internal doors for someone using a wheelchair or mobility aid to approach and open them?"],"priorityActions":[{"questionId":"2.3-1-1","questionText":"Are main circulation paths at least 1 metre wide?","action":"Measure all primary circulation paths and widen any below 1000mm clear width to comply with AS 1428.1 Clause 6 and the Premises Standards.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.3-1-2","questionText":"Are paths kept clear of obstacles and trip hazards (e.g., bins, plant pots, or furniture)?","action":"Conduct a walk-through audit to identify and remove all obstacles, protruding objects, and trip hazards from circulation paths, including temporary items like bins, signage, and stock.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.3-D-5","questionText":"Is there clear wayfinding signage to key destinations within your venue (toilets, lifts, service areas)?","action":"Install clear wayfinding signage directing visitors to key internal destinations: toilets, lifts, reception, accessible routes, and main service areas. Use consistent styling, high contrast, and standard symbols. Position signs at every decision point.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.3-D-9","questionText":"Is there tactile or auditory wayfinding for people with vision impairment?","action":"Install tactile wayfinding elements (TGSIs per AS 1428.4.1, tactile signs with Braille and raised lettering per AS 1428.1 Cl 8) at key locations. Consider auditory cues (talking signs, audio beacons) at main destinations. As a minimum, provide tactile room identification signs on accessible toilets, lifts, and exits.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Is there at least 2 metres of overhead clearance along all paths?"],"professionalReview":[]}'::jsonb,now() - interval '21 days',now() - interval '19 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-aquatic-leisure-centre','3.2','3.2','completed','mixed','{"doingWell":["Do you have at least one accessible toilet?","Are toilet doors easy to open and lock from inside?","Are baby change facilities accessible?"],"priorityActions":[{"questionId":"3.2-1-2","questionText":"Do you know where the nearest accessible toilet is?","action":"Identify the nearest accessible toilet (on-site or nearby), confirm its availability and compliance, and ensure all staff can direct customers to it.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.2-1-3","questionText":"Is toilet signage clear, with tactile and Braille elements where required?","action":"Install signage with tactile lettering, Braille, and the International Symbol of Access at each accessible toilet, positioned at 1200-1600mm height per AS 1428.1.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.2-1-4","questionText":"Is the accessible toilet kept clear of storage and obstacles?","action":"Remove all stored items (cleaning supplies, spare furniture, stock) from the accessible toilet and implement a policy prohibiting storage in the facility.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.2-1-5","questionText":"Is there an emergency alarm in the accessible toilet?","action":"Install an emergency alarm cord or button in the accessible toilet, reachable from floor level (per AS 1428.1 Clause 15), connected to a monitored alarm point, and test it regularly.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true}],"areasToExplore":["Can a wheelchair fit beside the toilet with enough room to transfer?"],"professionalReview":[]}'::jsonb,now() - interval '20 days',now() - interval '18 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-aquatic-leisure-centre','4.2','4.2','completed','mixed','{"doingWell":["Do staff know how to welcome and assist customers with assistance animals?","Do you have a process for customers to request assistance before arriving?","Are staff trained in various communication strategies?"],"priorityActions":[{"questionId":"4.2-F-6","questionText":"Do staff know where accessible facilities are located to direct customers?","action":"Ensure all staff know the location of accessible toilets, lifts, hearing loops, quiet spaces, accessible parking, and any other accessible facilities. Include this in onboarding and display a staff reference map.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-D-9","questionText":"Are staff trained to offer assistance without being condescending or over-helpful?","action":"Train staff to offer assistance respectfully: ask \"Can I help with anything?\" rather than assuming, speak directly to the customer (not their companion), and follow the customer''s lead on what help they want.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-D-10","questionText":"Do staff know how to communicate with customers who are Deaf or hard of hearing?","action":"Train staff on communicating with Deaf and hard of hearing customers: face them when speaking, reduce background noise, offer pen and paper, use gestures, and know how to book an Auslan interpreter when needed.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-D-11","questionText":"Is pen and paper available for written communication if needed?","action":"Keep pen and paper (or a whiteboard and marker) at all customer service points for written communication with customers who are Deaf, have speech disabilities, or prefer written exchange.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Have staff received disability awareness or inclusion training?","Do staff feel confident communicating with customers who have different needs?","Do staff know how to assist customers during an emergency evacuation?"],"professionalReview":[]}'::jsonb,now() - interval '19 days',now() - interval '17 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
