  values ('seed-redgum-aquatic-leisure-centre','4.4','4.4','completed','mixed','{"doingWell":["Do your emergency procedures include plans for people with disabilities?","Are emergency exits accessible to people with mobility aids?","Do staff know how to assist customers with different needs during an evacuation?"],"priorityActions":[{"questionId":"4.4-1-3","questionText":"Are there visual and audible alarms for emergencies?","action":"Install dual-mode alarm systems with both audible alarms and visual strobes (flashing lights) in all areas, including toilets and quiet spaces, per AS 1670.4 and Premises Standards.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true}],"areasToExplore":["Do you have Personal Emergency Evacuation Plans (PEEPs) for people who need them?","How do you communicate with Deaf visitors during an emergency?","Are emergency procedures displayed in accessible formats?"],"professionalReview":[]}'::jsonb,now() - interval '18 days',now() - interval '16 days',v_org,v_site,v_user,v_user)
