  values ('seed-redgum-aquatic-leisure-centre','4.1','4.1','completed','mixed','{"doingWell":["Are staff trained to communicate patiently with people who have speech disabilities, strong accents, or use AAC devices?","Is there a quiet space available for communication with customers who need a calmer environment?","Do you offer written confirmation or follow-up after important phone or in-person conversations?"],"priorityActions":[{"questionId":"4.1-PC-1","questionText":"Do you offer alternatives to phone calls for customers who cannot or prefer not to use voice telephone?","action":"Provide at least two non-phone contact options (e.g., email, live chat, SMS, online form). Under the DDA 1992, services must be accessible to people who cannot use voice telephone.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"4.1-PC-2","questionText":"Are your staff trained to receive calls via the National Relay Service (NRS)?","action":"Train all customer-facing staff to receive and handle National Relay Service (NRS) calls. Register with the NRS and display the NRS number alongside your main phone number.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.1-PC-3","questionText":"Do you capture and use customer communication preferences (preferred contact method, format needs)?","action":"Add a communication preferences field to your customer records (preferred contact method, format needs such as large print or Easy Read). Ask at first contact and store for future use.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.1-PC-9","questionText":"Can customers provide feedback or complaints through multiple accessible channels (not just an online form)?","action":"Offer at least three feedback channels (e.g., phone, email, in-person, mail, SMS). Ensure at least one does not require internet access and at least one does not require verbal communication.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do non-phone enquiries (email, text, chat) receive responses within the same timeframe as phone calls?","Do staff know what AAC (Augmentative and Alternative Communication) devices are and how to interact with users?","Where are customer communication preferences captured in your systems?"],"professionalReview":[]}'::jsonb,now() - interval '17 days',now() - interval '15 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
