  values ('seed-redgum-aquatic-leisure-centre','4.5','4.5','completed','mixed','{"doingWell":["Do you have a way for customers to provide feedback about accessibility?","Are your surveys and feedback forms accessible?","Do you actively monitor and respond to online reviews?"],"priorityActions":[{"questionId":"4.5-D-1","questionText":"Do you offer multiple ways for customers to provide feedback?","action":"Offer at least three feedback channels: online form, email, phone, in-person, and postal mail. Ensure at least one option does not require internet access and at least one does not require verbal communication.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.5-D-6","questionText":"Is there an escalation process for serious accessibility complaints?","action":"Document an escalation process for serious accessibility complaints. Define what constitutes a serious complaint (safety risk, discrimination allegation, repeated issue), who it escalates to, and the expected resolution timeframe.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.5-D-8","questionText":"Do you involve people with disabilities in reviewing or improving your services (e.g., advisory panel, co-design sessions, paid consultants)?","action":"Engage people with disabilities in reviewing and improving your services. Options include a paid advisory panel, co-design workshops, or commissioned reviews by disability consultants with lived experience. Ensure participants are compensated.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do you regularly review and act on accessibility feedback?"],"professionalReview":[]}'::jsonb,now() - interval '16 days',now() - interval '14 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-aquatic-leisure-centre','5.1','5.1','completed','mixed','{"doingWell":["Do you have a documented accessibility or disability inclusion policy?","Do you have a Disability Inclusion Action Plan (DIAP) or equivalent?","Is accessibility considered in your marketing and communications strategy?"],"priorityActions":[{"questionId":"5.1-F-4","questionText":"Do you accept the Companion Card for carers or support people?","action":"Register as a Companion Card affiliate. The scheme ensures carers and support people attend free of charge, removing a significant financial barrier. Contact your state or territory Companion Card program to enrol.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.1-F-5","questionText":"Do you have accessible pricing or concession options?","action":"Introduce concession pricing for people with disability. Consider free or discounted entry for Companion Card holders, pensioners, and NDIS participants. Make pricing information clear and easy to find.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.1-F-6","questionText":"Does your organisation have a policy on assistance animals?","action":"Establish a formal assistance animal policy immediately. Under the DDA 1992 and state legislation, refusing entry to an assistance animal is unlawful. Train all staff on their obligations, including recognising different types of accreditation.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"5.1-D-10","questionText":"Is there a dedicated budget for accessibility improvements?","action":"Allocate a dedicated budget line for accessibility improvements. Without ring-fenced funding, accessibility competes with other priorities and is often deprioritised. Include both capital works and ongoing operational costs.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do you maintain a single, named accessibility information register that all customer-facing channels reference?"],"professionalReview":[]}'::jsonb,now() - interval '15 days',now() - interval '13 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-aquatic-leisure-centre','5.9','5.9','completed','mixed','{"doingWell":["Do you use a workplace adjustment passport that travels with employees across role changes?","Are managers aware of and actively using JobAccess Employment Assistance Fund (EAF) for funded workplace modifications?","Is your onboarding content (documents, videos, induction sessions) available in accessible formats by default?"],"priorityActions":[{"questionId":"5.9-PC-1","questionText":"Do you proactively offer a workplace adjustment conversation to every new hire in their first two weeks?","action":"Add a workplace adjustment meeting to the onboarding checklist for every new hire. Train managers on how to run it.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.9-PC-6","questionText":"Do you have a clear, documented process for handling workplace adjustment requests, including timeframes and escalation?","action":"Draft a workplace adjustment process. Publish it. Train HR and managers.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"5.9-DD-4","questionText":"Are 30, 60, and 90-day check-ins structured to explicitly review adjustments, workload, and inclusion experience — not only performance?","action":"Design a structured 30/60/90 template with explicit adjustment prompts.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.9-DD-6","questionText":"Do first-time managers receive targeted training on supporting employees with disability before (or at) the point of first managing someone with a disclosed disability?","action":"Build a targeted module for first-time managers. Mandate before first disclosed report.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do new hires get a personalised induction plan that explicitly covers their adjustment needs and communication preferences?","Is assistive technology (screen reader, magnification, speech-to-text, ergonomic equipment) provisioned within 2 weeks of identified need?","Is there a return-to-work process specifically designed to support return after leave for disability-related reasons (injury, mental health, chronic illness flare)?"],"professionalReview":[]}'::jsonb,now() - interval '14 days',now() - interval '12 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;

  -- ===== Botanic Gardens & Playground =====
  select id into v_site from sites where organisation_id = v_org and name = 'Botanic Gardens & Playground';
  values ('seed-redgum-botanic-gardens-playground','2.1','2.1','completed','mixed','{"doingWell":["Do you have designated accessible parking spaces?","Are accessible parking spaces located close to the main entrance?","Is there a drop-off zone near the entrance for customers who need it?"],"priorityActions":[{"questionId":"2.1-F-6a","questionText":"Is there wayfinding signage from the parking area to the entrance?","action":"Install wayfinding signage from accessible parking to the entrance. Signs must include the ISA and directional arrows, be positioned at each turn or decision point, and comply with AS 1428.1 Cl 8 for height and contrast.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-7","questionText":"Do staff know how to direct customers to accessible parking and entry points?","action":"Train all customer-facing staff on the location of accessible parking, the accessible entry route, and how to provide clear directions. Include this in induction and refresher training. Provide a simple reference map at reception.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.1-D-9","questionText":"During busy periods, special events or temporary setups, are accessible parking spaces still available and not blocked?","action":"Implement measures to protect accessible parking spaces during busy periods. Options include bollards, clear \"no standing\" enforcement, staff monitoring, and traffic management plans that explicitly address accessible bays.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Is the drop-off zone level and easy to access from the footpath?","Is the path to your entrance wide enough for people using mobility aids, walking with companions or using service animals (at least 1 metre wide)?","Is the path to the entrance protected from weather (covered or sheltered)?"],"professionalReview":[]}'::jsonb,now() - interval '13 days',now() - interval '11 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-botanic-gardens-playground','2.3','2.3','completed','mixed','{"doingWell":["Does your venue have any internal level changes? Select all that apply:","Is there at least 2 metres of overhead clearance along all paths?","Is there enough space for two people to pass each other, or for a wheelchair to turn around?"],"priorityActions":[{"questionId":"2.3-1-1","questionText":"Are main circulation paths at least 1 metre wide?","action":"Measure all primary circulation paths and widen any below 1000mm clear width to comply with AS 1428.1 Clause 6 and the Premises Standards.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.3-1-2","questionText":"Are paths kept clear of obstacles and trip hazards (e.g., bins, plant pots, or furniture)?","action":"Conduct a walk-through audit to identify and remove all obstacles, protruding objects, and trip hazards from circulation paths, including temporary items like bins, signage, and stock.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.3-D-23","questionText":"Do floor surfaces and internal doors contrast with walls to help people with low vision orient themselves?","action":"Increase visual contrast between floor surfaces, internal doors, and walls. Doors and frames should contrast with the adjacent wall by at least 30% luminance. Use contrasting floor colours or materials at transitions. Avoid monochrome colour schemes throughout.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.3-D-24","questionText":"Are floor surfaces level, well-maintained, and free from trip hazards such as cracked tiles, lifted edges, or abrupt thresholds?","action":"Survey all floor surfaces for trip hazards including cracked tiles, lifted edges, loose carpet, cable runs, and abrupt thresholds. Repair or replace damaged surfaces, secure loose edges, and install cable covers. Establish a regular inspection schedule to catch new hazards promptly.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true}],"areasToExplore":["Are floor surfaces slip-resistant, especially in areas that may get wet?"],"professionalReview":[]}'::jsonb,now() - interval '12 days',now() - interval '10 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-botanic-gardens-playground','3.5','3.5','completed','mixed','{"doingWell":["Do key signs include tactile lettering and Braille?","Do signs have adequate colour contrast between text and background?","Is there directional signage at key decision points throughout the venue?"],"priorityActions":[{"questionId":"3.5-1-1","questionText":"Is signage clear, with good contrast and readable font sizes?","action":"Audit all signage for contrast (minimum 3:1 for large text per AS 1428.1), font size (minimum 15mm character height at 1m reading distance), and sans-serif typeface legibility.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.5-1-2","questionText":"Are signs placed at consistent heights and locations?","action":"Standardise sign mounting heights between 1200mm and 1600mm (eye level range per AS 1428.1) and place signs consistently on the same side of doorways throughout the venue.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.5-1-3","questionText":"Are accessible facilities (toilets, lifts) clearly signed?","action":"Install clear directional signage to all accessible facilities (toilets, lifts, parking, entrances) using the International Symbol of Access, tactile lettering, and Braille per AS 1428.1.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Would a first-time visitor be able to navigate independently?","Is there a map, floor plan, or directory showing the layout and key facilities?"],"professionalReview":[]}'::jsonb,now() - interval '11 days',now() - interval '9 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-botanic-gardens-playground','4.1','4.1','completed','mixed','{"doingWell":["Are your staff trained to receive calls via the National Relay Service (NRS)?","Are staff trained to communicate patiently with people who have speech disabilities, strong accents, or use AAC devices?","Do staff know what AAC (Augmentative and Alternative Communication) devices are and how to interact with users?"],"priorityActions":[{"questionId":"4.1-PC-1","questionText":"Do you offer alternatives to phone calls for customers who cannot or prefer not to use voice telephone?","action":"Provide at least two non-phone contact options (e.g., email, live chat, SMS, online form). Under the DDA 1992, services must be accessible to people who cannot use voice telephone.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"4.1-PC-3","questionText":"Do you capture and use customer communication preferences (preferred contact method, format needs)?","action":"Add a communication preferences field to your customer records (preferred contact method, format needs such as large print or Easy Read). Ask at first contact and store for future use.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.1-PC-4","questionText":"Do non-phone enquiries (email, text, chat) receive responses within the same timeframe as phone calls?","action":"Set and enforce equivalent service-level agreements for non-phone channels. If phone calls are answered within 2 minutes, email and chat should receive responses within the same window.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.1-PC-8","questionText":"Do you offer written confirmation or follow-up after important phone or in-person conversations?","action":"Offer written confirmation (email, SMS, or letter) after important phone or in-person conversations covering bookings, service changes, or access arrangements.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Where are customer communication preferences captured in your systems?","What training have staff received on communicating with people who have speech differences?"],"professionalReview":[]}'::jsonb,now() - interval '10 days',now() - interval '8 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-botanic-gardens-playground','4.4','4.4','completed','mixed','{"doingWell":["Are emergency exits accessible to people with mobility aids?","Are there visual and audible alarms for emergencies?","Do staff know how to assist customers with different needs during an evacuation?"],"priorityActions":[{"questionId":"4.4-1-1","questionText":"Do your emergency procedures include plans for people with disabilities?","action":"Update your emergency management plan to include specific procedures for evacuating people with mobility, sensory, cognitive, and psychosocial disabilities per DDA 1992 obligations.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"4.4-D-8","questionText":"How often are evacuation drills conducted, and do they include disability scenarios?","action":"Conduct evacuation drills at least every six months that include disability scenarios: evacuating a wheelchair user, guiding a blind person, communicating with a Deaf visitor, and supporting a person with cognitive disability. Document outcomes and improve procedures based on findings.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true}],"areasToExplore":["Do you have Personal Emergency Evacuation Plans (PEEPs) for people who need them?","How do you communicate with Deaf visitors during an emergency?","Are emergency procedures displayed in accessible formats?"],"professionalReview":[]}'::jsonb,now() - interval '9 days',now() - interval '7 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-botanic-gardens-playground','4.6','4.6','completed','mixed','{"doingWell":["Are your marketing emails and newsletters accessible?","Can customers easily manage their communication preferences?","Are your promotional offers and discounts accessible to everyone?"],"priorityActions":[{"questionId":"4.6-D-1","questionText":"Do you offer SMS or text alternatives to email communications?","action":"Offer SMS or text message alternatives to email for key communications: appointment reminders, booking confirmations, service updates, and promotional offers. Allow customers to opt in to SMS as their preferred channel.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.6-D-3","questionText":"Do you include accessibility information in your ongoing communications?","action":"Include accessibility information in your regular customer communications: mention accessible facilities in newsletters, highlight new accessibility features in updates, and include access details in event promotions.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.6-D-4","questionText":"Are your social media posts accessible?","action":"Make your social media posts accessible: add alt text to all images, caption all videos, use camelCase hashtags (e.g., #AccessibleDesign), avoid conveying information through colour alone, and write in plain language. Avoid flashing or rapidly moving content.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"4.6-D-7","questionText":"Do you notify customers when you make accessibility improvements?","action":"Communicate accessibility improvements to customers: update your website, send targeted notifications to customers who previously flagged related needs, post on social media, and include in newsletters.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Is your video content captioned and audio-described?","Are your event invitations and RSVPs accessible?"],"professionalReview":[]}'::jsonb,now() - interval '8 days',now() - interval '6 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-botanic-gardens-playground','3.11','3.11','completed','mixed','{"doingWell":["Are outdoor paths and walkways firm, level, and wide enough for a person using a wheelchair or mobility aid?","Is outdoor seating available at different heights and types, including options accessible to wheelchair users?","Are outdoor areas well-lit for evening or low-light use?"],"priorityActions":[{"questionId":"3.11-D-4","questionText":"Are outdoor drinking fountains or water stations at accessible heights with easy-to-operate controls?","action":"Install or retrofit at least one drinking fountain at wheelchair-accessible height (750-800mm) with lever or push-button controls. Ensure clear approach space for wheelchair users.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.11-D-7","questionText":"Do outdoor areas provide quiet or low-stimulation zones for people who need a sensory break?","action":"Designate a quiet outdoor area away from main activity zones, with seating, shade, and natural screening. Mark it on your venue map.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.11-D-8","questionText":"Are outdoor dining areas accessible, including table heights, surface access, and space for wheelchair users?","action":"Provide accessible outdoor dining tables (750-800mm height, 700mm knee clearance, no centre pedestal), ensure level ground surfaces, and maintain 1200mm circulation space between tables.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.11-D-9","questionText":"Are accessible toilets available within a reasonable distance of outdoor areas, with clear signage directing visitors to them?","action":"Provide accessible toilets within reasonable distance (approximately 100m) of outdoor areas, ensure an accessible path connects them, and install clear directional signage with the ISA.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Is shade or weather protection available in key outdoor areas?","Can customers access key outdoor areas without needing to use stairs?","Do garden beds, planters, or landscaping features maintain clear path widths of at least 1200mm?"],"professionalReview":[]}'::jsonb,now() - interval '7 days',now() - interval '5 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-botanic-gardens-playground','3.12','3.12','completed','mixed','{"doingWell":["Is the playground surface firm and level enough for wheelchair or mobility aid access to reach play equipment?","Is the playground fenced or enclosed to support children who may run, wander, or need containment?","Is accessible seating with shade provided near the playground for caregivers?"],"priorityActions":[{"questionId":"3.12-PC-3","questionText":"Does the playground include equipment that children of different abilities can use together?","action":"Add inclusive play equipment (basket swings, flush carousels, ground-level trampolines, sensory panels) alongside standard equipment. Ensure all-abilities equipment is co-located, not separated.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.12-PC-4","questionText":"Does the playground include sensory play elements alongside physical equipment?","action":"Add sensory play elements (musical instruments, sand and water play, textured panels, nature play) alongside physical equipment. Ensure sensory elements are reachable from a seated position.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.12-D-1","questionText":"Are transfer platforms or ramps provided so children can move from wheelchairs onto elevated play equipment?","action":"Install a transfer platform or ramp on at least one elevated play structure. Position it at wheelchair seat height with a firm approach surface and connect it to a meaningful play experience.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.12-D-5","questionText":"Is the playground surface compliant with Australian Standards for impact attenuation and accessibility?","action":"Assess playground surfaces against AS 4422 (impact attenuation) and AS 4685 (general requirements). Upgrade to rubber soft fall or other compliant surfaces on key routes and fall zones.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Is there an accessible path connecting the playground to car parking, toilets, and other facilities?","Is there a quiet zone or calm space near the playground for children who become overstimulated?","Does the playground provide a range of play experiences at different heights and challenge levels, so children can progress as their abilities develop?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;

  -- ===== Winter Markets =====
  select id into v_site from sites where organisation_id = v_org and name = 'Winter Markets';
  values ('seed-redgum-winter-markets','1.1','1.1','completed','mixed','{"doingWell":["Do you have accessibility information available for customers before they visit?","Do you invite feedback about the accuracy of your accessibility information?"],"priorityActions":[{"questionId":"1.1-F-3B","questionText":"How confident are you that this information is accurate and up to date?","action":"Establish a process to verify the accuracy of your accessibility information. Conduct a physical walkthrough of your venue comparing published details against actual conditions.","priority":"medium","timeframe":"30-90 days"},{"questionId":"1.1-D-3a","questionText":"When was your accessibility information last reviewed or updated?","action":"Schedule an immediate review of your accessibility information and establish a regular review cycle (at minimum every 6 months, or whenever physical changes occur at your venue).","priority":"medium","timeframe":"30-90 days"},{"questionId":"1.1-D-9","questionText":"Is your accessibility information consistent across all platforms?","action":"Audit all platforms where your accessibility information appears and ensure consistency. Discrepancies between your website, Google listing, social media, and third-party platforms create confusion and erode trust.","priority":"high","timeframe":"30-90 days"},{"questionId":"1.1-D-10","questionText":"Do you clearly state limitations or barriers that still exist?","action":"Clearly state any known barriers or limitations on your accessibility page. Customers with disability prefer honest information about what is not accessible so they can plan accordingly, rather than discovering barriers on arrival.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["What''s currently a barrier for you to share accessibility information?","Where would it be easiest to start sharing accessibility information?","What types of accessibility information do you currently share?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-winter-markets','2.1','2.1','completed','needs-work','{"doingWell":["Do you have designated accessible parking spaces?","Are accessible parking spaces located close to the main entrance?","Is the path from accessible parking to the entrance smooth and level?"],"priorityActions":[{"questionId":"2.1-F-3","questionText":"Is there a drop-off zone near the entrance for customers who need it?","action":"Establish a designated drop-off zone near the main entrance. Mark it clearly with signage and ensure it connects to the accessible path of travel. Consider a minimum 6000mm length to accommodate larger accessible vehicles.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.1-F-3a","questionText":"Is the drop-off zone level and easy to access from the footpath?","action":"Regrade or modify the drop-off zone to provide a firm, level surface flush with the adjacent footpath. Install a kerb ramp or dropped kerb per AS 1428.1 Cl 10 if there is a level change between the roadway and the path.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-5","questionText":"Is the path to your entrance wide enough for people using mobility aids, walking with companions or using service animals (at least 1 metre wide)?","action":"Widen the path to at least 1000mm clear width (1200mm preferred, 1800mm at passing points) per AS 1428.1 Cl 7. Remove any obstructions that narrow the effective width, including overhanging vegetation, bins, or signage.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-6","questionText":"Is there directional signage on the road approach directing visitors to accessible parking?","action":"Install directional signage on the road approach indicating the location of accessible parking. Use the International Symbol of Access (ISA) with a directional arrow, visible from the vehicle approach. Position signs at each decision point.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values (v_org,v_site,'2.1','2.1','seed-run-redgum-winter-markets-2.1-r1','{"type":"general","name":"Initial assessment (2026)"}'::jsonb,'completed', now() - interval '210 days', now() - interval '208 days','needs-work','{"doingWell":["Is there wayfinding signage from the parking area to the entrance?","Is the surface of accessible parking spaces firm and slip-resistant?","Are accessible parking spaces clearly marked with both ground markings and vertical signage?"],"priorityActions":[{"questionId":"2.1-F-1","questionText":"Do you have designated accessible parking spaces?","action":"Provide designated accessible parking spaces. Under the Premises Standards and AS/NZS 2890.6, at least one accessible space is required. Each space must be min 2400mm wide with a 2400mm shared area (or 3200mm for a single space) and 5400mm long.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-3","questionText":"Is there a drop-off zone near the entrance for customers who need it?","action":"Establish a designated drop-off zone near the main entrance. Mark it clearly with signage and ensure it connects to the accessible path of travel. Consider a minimum 6000mm length to accommodate larger accessible vehicles.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.1-F-4","questionText":"Is the path from accessible parking to the entrance smooth and level?","action":"Resurface or regrade the path from accessible parking to the entrance to provide a continuous accessible path of travel. The surface must be firm, slip-resistant, and free of trip hazards per AS 1428.1 Cl 7. Maximum crossfall is 1:40.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.1-F-6","questionText":"Is there directional signage on the road approach directing visitors to accessible parking?","action":"Install directional signage on the road approach indicating the location of accessible parking. Use the International Symbol of Access (ISA) with a directional arrow, visible from the vehicle approach. Position signs at each decision point.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Are accessible parking spaces located close to the main entrance?","Is the drop-off zone level and easy to access from the footpath?","Is the path to your entrance wide enough for people using mobility aids, walking with companions or using service animals (at least 1 metre wide)?"],"professionalReview":[]}'::jsonb,'[{"questionId":"2.1-F-1","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-2","answer":"unable-to-check","notes":"Not sure this has been checked since the last refurbishment.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-3","answer":"partially","partialDescription":"Accessible toilet available but the change table is not adult-sized.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-3a","answer":"unable-to-check","notes":"Need to confirm current measurements with the facilities team.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-4","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-5","answer":"unable-to-check","notes":"Not sure this has been checked since the last refurbishment.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-6","answer":"partially","partialDescription":"Accessible toilet available but the change table is not adult-sized.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-6a","answer":"yes","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-6b","answer":"partially","partialDescription":"Staff had training in 2023; a refresher is scheduled but not yet booked.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-7","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-F-8","answer":"no","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-D-9","answer":"partially","partialDescription":"Large-print materials available on request but not routinely offered.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-D-9a","answer":"yes","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-D-9c","answer":"partially","partialDescription":"Signage is clear at the entry but wayfinding inside is inconsistent.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-D-13","answer":"yes","notes":"Verified with the venue coordinator.","timestamp":"2026-01-15T00:00:00.000Z"},{"questionId":"2.1-D-10","answer":"yes","timestamp":"2026-01-15T00:00:00.000Z"}]'::jsonb,v_user)
  on conflict (run_id) do nothing;
  values ('seed-redgum-winter-markets','2.4','2.4','completed','mixed','{"doingWell":["Do staff know how to accommodate customers who need queue assistance?","Is there signage indicating that queue assistance is available for those who need it?","Do you offer alternative queue arrangements (e.g., text notification, numbered tickets)?"],"priorityActions":[{"questionId":"2.4-1-1","questionText":"Is there seating available in queue areas for people who cannot stand for long?","action":"Install or provide portable seating in queue areas for people who cannot stand for extended periods, positioned so they can maintain their place in the queue.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.4-1-2","questionText":"Can customers request priority access when needed?","action":"Establish a clear priority access process, train all customer-facing staff to offer it, and display signage informing customers that priority access is available.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.4-1-2a","questionText":"Is there a streamlined or dedicated accessible entry option that bypasses the main queue?","action":"Create a streamlined accessible entry pathway that bypasses the main queue, with clear signage and staff awareness so customers can use it independently.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.4-D-4","questionText":"Is the queue layout accessible for wheelchair users and people with mobility aids?","action":"Redesign the queue layout to provide at least 1000mm clear width throughout, a 2070mm turning circle at the service point, and no barriers that impede wheelchairs (e.g., narrow stanchion spacing, high rope barriers). Ensure the queue path is level with a firm surface.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Do you communicate expected wait times to customers?","Is information about queuing and busy periods available before visitors arrive?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-winter-markets','3.5','3.5','completed','mixed','{"doingWell":["Are signs placed at consistent heights and locations?","Do key signs include tactile lettering and Braille?","Is there directional signage at key decision points throughout the venue?"],"priorityActions":[{"questionId":"3.5-1-1","questionText":"Is signage clear, with good contrast and readable font sizes?","action":"Audit all signage for contrast (minimum 3:1 for large text per AS 1428.1), font size (minimum 15mm character height at 1m reading distance), and sans-serif typeface legibility.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.5-1-3","questionText":"Are accessible facilities (toilets, lifts) clearly signed?","action":"Install clear directional signage to all accessible facilities (toilets, lifts, parking, entrances) using the International Symbol of Access, tactile lettering, and Braille per AS 1428.1.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.5-1-4","questionText":"Would a first-time visitor be able to navigate independently?","action":"Walk through your venue as a first-time visitor and note every decision point where signage is missing, confusing, or not visible, then add directional signage at each.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.5-D-5","questionText":"Is there clear signage on the approach to your venue and at the entrance?","action":"Install clear, high-contrast signage on the approach to your venue and at the entrance. Include the venue name, entrance location, and international accessibility symbols where relevant. Ensure signs are visible from the street and car park.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do signs have adequate colour contrast between text and background?","Do you use pictures, symbols, or Easy Read formats alongside text on key signs?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-winter-markets','4.2','4.2','completed','mixed','{"doingWell":["Do staff know how to welcome and assist customers with assistance animals?","Do you have a process for customers to request assistance before arriving?","Do staff know where accessible facilities are located to direct customers?"],"priorityActions":[{"questionId":"4.2-F-3","questionText":"Do staff feel confident communicating with customers who have different needs?","action":"Provide practical communication training covering interactions with people who are Deaf, blind, have intellectual disabilities, use wheelchairs, or have speech differences. Include role-play exercises.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-F-5","questionText":"Are staff trained in various communication strategies?","action":"Train staff in varied communication strategies: speaking clearly and at a moderate pace, using plain language, offering written information, using gestures or visual aids, and adjusting approach based on customer cues.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-D-13","questionText":"Is there a quiet space available for customers who become overwhelmed?","action":"Designate a quiet, low-stimulus space where customers who become overwhelmed can decompress. Ensure staff know where it is and can offer it proactively when a customer appears distressed.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-D-15","questionText":"Is accessibility training included in new staff onboarding?","action":"Include accessibility and disability awareness training as a mandatory component of new staff onboarding. Cover assistance animal rights, communication strategies, accessible facility locations, and your complaints process.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Have staff received disability awareness or inclusion training?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-winter-markets','4.4','4.4','completed','mixed','{"doingWell":["Do your emergency procedures include plans for people with disabilities?","Are emergency exits accessible to people with mobility aids?","Are there visual and audible alarms for emergencies?"],"priorityActions":[{"questionId":"4.4-D-1","questionText":"Do you have Personal Emergency Evacuation Plans (PEEPs) for people who need them?","action":"Implement Personal Emergency Evacuation Plans (PEEPs) for staff and regular visitors who need them. For casual visitors, develop generic PEEPs covering common disability types (wheelchair user, blind person, Deaf person). This is a mandatory safety requirement under Australian workplace and building legislation.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true}],"areasToExplore":["How do you communicate with Deaf visitors during an emergency?","Are emergency procedures displayed in accessible formats?","Can you communicate visitor disability needs to external emergency services when they arrive?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-winter-markets','4.7','4.7','completed','mixed','{"doingWell":["Do you have accessible document templates (Word, InDesign) for staff to use?","Do you remember and apply customer communication preferences for ongoing correspondence?","Have you tested your emails for accessibility (screen reader, images disabled)?"],"priorityActions":[{"questionId":"4.7-PC-1","questionText":"Are your written communications (letters, emails, invoices) designed to be clear and accessible?","action":"Review your written communications (letters, emails, invoices) for accessibility: use minimum 12pt sans-serif font, left-aligned text, clear headings, plain language, and adequate white space. Avoid justified text and decorative fonts.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.7-PC-4","questionText":"Do you have accessible email templates that staff use for customer communications?","action":"Create accessible email templates for common customer communications (booking confirmations, receipts, newsletters, service updates). Include proper heading structure, alt text placeholders, high-contrast design, and meaningful link text.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.7-PC-6","questionText":"Can customers request important documents in alternative formats (large print, audio, Easy Read)?","action":"Establish a process for providing important documents in alternative formats on request: large print (minimum 18pt), audio (recorded or synthesised), Easy Read, Braille (via a transcription service), and accessible digital (tagged PDF, HTML). Set turnaround time targets.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.7-DD-3b","questionText":"Do staff who create documents know how to use heading styles, alt text, and proper structure?","action":"Create accessible document templates with built-in heading styles, alt text prompts, and correct table structure. Add an accessibility checklist to your document review process.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Are your emails designed for accessibility (readable without images, proper headings, plain text option)?","Are your PDF documents and attachments created accessibly (tagged, proper headings, alt text)?","Are your mailing lists and subscription options accessible (email preferences, unsubscribe options)?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-winter-markets','6.1','6.1','completed','mixed','{"doingWell":["Can attendees request accessibility accommodations during registration?","Are Companion Card holders offered free or discounted companion tickets?","Do you offer discounted or free tickets for people with disability?"],"priorityActions":[{"questionId":"6.1-PC-2","questionText":"Does your event promotion include accessibility information?","action":"Add accessibility details to all event promotion materials, including what accommodations are available, how to request support, and who to contact. This should appear on your event website, social media, and printed collateral.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"6.1-D-1","questionText":"Have you set an accessibility budget for this event?","action":"Allocate a specific accessibility budget line item for your event. Include Auslan interpreters, captioning, hearing augmentation, accessible materials, equipment hire, and contingency for on-the-day requests. A typical allocation is 5-15% of overall event budget.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"6.1-D-2","questionText":"Have people with disability been consulted in planning this event?","action":"Engage people with disability in your event planning process. This could include a disability advisory group, paid consultants with lived experience, or partnerships with disability organisations. Consultation should happen early enough to influence decisions.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"6.1-D-5","questionText":"What is the deadline for accessibility accommodation requests?","action":"Set a clear deadline for accommodation requests (typically 2-4 weeks before the event) and communicate it prominently. Also establish a process for handling late or on-the-day requests, as some needs cannot be anticipated in advance.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Has accessibility been considered in the early planning stages of this event?","What information is provided in your event accessibility statement?","Are your promotional materials available in accessible formats?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-winter-markets','6.2','6.2','completed','mixed','{"doingWell":["Is the event venue physically accessible for wheelchair users?","Is there accessible parking or drop-off available?","Are there accessible toilets available at the event?"],"priorityActions":[{"questionId":"6.2-PC-5","questionText":"Is there a quiet space or low-sensory area available?","action":"Designate a quiet or low-sensory space away from the main event area. It should have comfortable seating, reduced lighting, minimal noise, and be staffed or monitored. Clearly sign and promote its location in event materials.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"6.2-D-2","questionText":"Is the stage or presentation area accessible?","action":"Ensure the stage or presentation area has step-free access via a ramp (1:14 gradient or gentler) or platform lift. Provide an accessible lectern with adjustable height, adequate lighting on the presenter, and hearing augmentation coverage.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"6.2-D-3","questionText":"Is there a Changing Places facility at or near the venue?","action":"Check the Changing Places website (changingplaces.org.au) for a facility near your venue. If none is nearby, consider hiring a temporary Changing Places unit for large events. Communicate the nearest facility location in your event accessibility information.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"6.2-D-7","questionText":"Is there accessible viewing for standing events?","action":"Provide designated accessible viewing areas at standing events. These should offer clear sightlines to the stage, be on level firm ground, include companion spaces, and be protected from crowd crush. Position them where the atmosphere is still part of the event experience.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["What seating options are available for people with disability?","What accessible transport options can attendees use?","Are surfaces and terrain accessible for mobility aids?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;

  -- ===== Riverbend Summer Festival =====
  select id into v_site from sites where organisation_id = v_org and name = 'Riverbend Summer Festival';
  values ('seed-redgum-riverbend-summer-festival','1.1','1.1','completed','mixed','{"doingWell":["Do you have accessibility information available for customers before they visit?","How confident are you that this information is accurate and up to date?","Has your accessibility information been checked against any of these sources?"],"priorityActions":[{"questionId":"1.1-D-3a","questionText":"When was your accessibility information last reviewed or updated?","action":"Schedule an immediate review of your accessibility information and establish a regular review cycle (at minimum every 6 months, or whenever physical changes occur at your venue).","priority":"medium","timeframe":"30-90 days"},{"questionId":"1.1-D-10","questionText":"Do you clearly state limitations or barriers that still exist?","action":"Clearly state any known barriers or limitations on your accessibility page. Customers with disability prefer honest information about what is not accessible so they can plan accordingly, rather than discovering barriers on arrival.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.1-D-12","questionText":"Who is responsible for maintaining your accessibility information?","action":"Assign a specific person or role as responsible for maintaining your accessibility information. Without clear ownership, information becomes outdated and inaccurate.","priority":"medium","timeframe":"30-90 days"},{"questionId":"1.1-F-5","questionText":"Can customers contact you in a variety of ways to ask accessibility questions before visiting?","action":"Provide multiple ways for customers to ask accessibility questions before visiting, such as phone, email, online chat, contact form, and social media messaging. Relying on a single channel excludes customers who cannot use that method.","priority":"high","timeframe":"30-90 days"}],"areasToExplore":["What''s currently a barrier for you to share accessibility information?","Where would it be easiest to start sharing accessibility information?","What types of accessibility information do you currently share?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverbend-summer-festival','1.4','1.4','completed','needs-work','{"doingWell":["Do you add alt text or image descriptions to each image in carousel or multi-image posts?","Do videos autoplay on your website or social media?","Are your captions accurately synchronised with the audio?"],"priorityActions":[{"questionId":"1.4-PC-1","questionText":"Do your videos have captions or subtitles?","action":"Add captions or subtitles to all published videos, as required by WCAG 2.2 Success Criterion 1.2.2 (Captions - Prerecorded). Captions are essential for Deaf and hard of hearing viewers and benefit many others in noisy or sound-restricted environments.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.4-PC-2","questionText":"Do your videos include audio descriptions for important visual content?","action":"Add audio descriptions to videos where important visual content is not conveyed through the existing audio track, per WCAG 2.2 Success Criterion 1.2.5 (Audio Description - Prerecorded). Describe key actions, text on screen, and scene changes.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.4-PC-3","questionText":"Do you include alt text or image descriptions when posting images on social media?","action":"Add descriptive alt text or image descriptions to all images posted on social media. Most platforms (Instagram, Facebook, X/Twitter, LinkedIn) support alt text natively. Describe the content and context of the image, not just \"photo\" or \"image.\"","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.4-PC-4","questionText":"Can users control video playback using keyboard, screen readers, or other assistive technology?","action":"Ensure all video players on your website support keyboard controls and are compatible with screen readers and other assistive technology, per WCAG 2.2 Success Criterion 2.1.1 (Keyboard). Users must be able to play, pause, adjust volume, and toggle captions without a mouse.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["What type of captions do you use for your videos?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverbend-summer-festival','2.1','2.1','completed','needs-work','{"doingWell":["Is the drop-off zone level and easy to access from the footpath?","Is the path to your entrance wide enough for people using mobility aids, walking with companions or using service animals (at least 1 metre wide)?","If the accessible route differs from the main pedestrian path, is it clearly signed?"],"priorityActions":[{"questionId":"2.1-F-1","questionText":"Do you have designated accessible parking spaces?","action":"Provide designated accessible parking spaces. Under the Premises Standards and AS/NZS 2890.6, at least one accessible space is required. Each space must be min 2400mm wide with a 2400mm shared area (or 3200mm for a single space) and 5400mm long.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-2","questionText":"Are accessible parking spaces located close to the main entrance?","action":"Relocate or designate accessible parking spaces as close as practicable to the main entrance. AS/NZS 2890.6 recommends the shortest practicable route. Prioritise spaces nearest to the accessible entry path.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-3","questionText":"Is there a drop-off zone near the entrance for customers who need it?","action":"Establish a designated drop-off zone near the main entrance. Mark it clearly with signage and ensure it connects to the accessible path of travel. Consider a minimum 6000mm length to accommodate larger accessible vehicles.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.1-F-6","questionText":"Is there directional signage on the road approach directing visitors to accessible parking?","action":"Install directional signage on the road approach indicating the location of accessible parking. Use the International Symbol of Access (ISA) with a directional arrow, visible from the vehicle approach. Position signs at each decision point.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Is the path from accessible parking to the entrance smooth and level?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverbend-summer-festival','2.4','2.4','completed','needs-work','{"doingWell":["Is there seating available in queue areas for people who cannot stand for long?","Is there a streamlined or dedicated accessible entry option that bypasses the main queue?","Do staff know how to accommodate customers who need queue assistance?"],"priorityActions":[{"questionId":"2.4-1-2","questionText":"Can customers request priority access when needed?","action":"Establish a clear priority access process, train all customer-facing staff to offer it, and display signage informing customers that priority access is available.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.4-D-4","questionText":"Is the queue layout accessible for wheelchair users and people with mobility aids?","action":"Redesign the queue layout to provide at least 1000mm clear width throughout, a 2070mm turning circle at the service point, and no barriers that impede wheelchairs (e.g., narrow stanchion spacing, high rope barriers). Ensure the queue path is level with a firm surface.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.4-D-5","questionText":"Is there signage indicating that queue assistance is available for those who need it?","action":"Install clear signage at the entrance to queue areas stating that assistance is available for people who need it. Include the ISA and a brief message such as \"Ask a team member for queue assistance.\" Position signs at eye level (1400-1600mm).","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.4-D-6","questionText":"Do you offer alternative queue arrangements (e.g., text notification, numbered tickets)?","action":"Introduce at least one alternative queue option, such as SMS or app-based notification, a numbered ticket system, call-ahead registration, or a dedicated \"queue from seated\" option. Advertise the alternative clearly with signage and on your website.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Is information about queuing and busy periods available before visitors arrive?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverbend-summer-festival','3.6','3.6','completed','mixed','{"doingWell":["Are digital alternatives available (QR codes, online menus)?","Do you offer Braille versions of any materials?","Do you provide tactile maps or models?"],"priorityActions":[{"questionId":"3.6-1-1","questionText":"Are large print versions of key materials available?","action":"Produce large print versions (minimum 18pt, sans-serif font) of key customer-facing documents such as menus, brochures, forms, and pricelists.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.6-1-2","questionText":"Can staff read menus or materials aloud for customers who need it?","action":"Train staff to offer to read menus, forms, and information aloud to customers, using clear speech, appropriate pace, and privacy awareness.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.6-D-1","questionText":"Do your QR codes link to accessible content?","action":"Ensure all QR code destinations are WCAG 2.2 AA compliant: proper heading structure, alt text for images, sufficient colour contrast, keyboard navigable, and compatible with screen readers. Test with VoiceOver and TalkBack.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.6-D-2","questionText":"Are your QR codes large enough and well-positioned?","action":"Resize QR codes to at least 30x30mm and position between 900-1200mm height, reachable from a seated position, on a contrasting background, and away from glare. Add a short text description of where the code leads.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do you offer key information in alternative formats such as Easy Read or Plain English?","Are dietary requirements and allergens clearly labelled on menus?","Are videos and multimedia content captioned?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverbend-summer-festival','4.2','4.2','completed','needs-work','{"doingWell":["Do staff know how to welcome and assist customers with assistance animals?","Do staff feel confident communicating with customers who have different needs?","Do staff know where accessible facilities are located to direct customers?"],"priorityActions":[{"questionId":"4.2-F-4","questionText":"Do you have a process for customers to request assistance before arriving?","action":"Create a process for customers to request assistance before arriving. Include it in your booking flow, on your website contact page, and in booking confirmations. Nominate a staff member to action requests.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-F-5","questionText":"Are staff trained in various communication strategies?","action":"Train staff in varied communication strategies: speaking clearly and at a moderate pace, using plain language, offering written information, using gestures or visual aids, and adjusting approach based on customer cues.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-F-7","questionText":"Is there a clear process for handling accessibility complaints or feedback?","action":"Document a clear process for handling accessibility complaints and feedback. Include who receives them, response timeframes, escalation paths, and how outcomes are communicated back to the customer.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.2-D-11","questionText":"Is pen and paper available for written communication if needed?","action":"Keep pen and paper (or a whiteboard and marker) at all customer service points for written communication with customers who are Deaf, have speech disabilities, or prefer written exchange.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Have staff received disability awareness or inclusion training?","Are staff trained to offer assistance without being condescending or over-helpful?","Do staff know how to communicate with customers who are Deaf or hard of hearing?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverbend-summer-festival','4.7','4.7','completed','mixed','{"doingWell":["Are your written communications (letters, emails, invoices) designed to be clear and accessible?","Are your PDF documents and attachments created accessibly (tagged, proper headings, alt text)?","Do you have accessible email templates that staff use for customer communications?"],"priorityActions":[{"questionId":"4.7-PC-5","questionText":"Do you have accessible document templates (Word, InDesign) for staff to use?","action":"Create accessible Word and InDesign templates for all common document types: letters, reports, flyers, menus, and forms. Include pre-set heading styles, alt text prompts, accessible colour palettes, and minimum 12pt body text.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.7-PC-7","questionText":"Do you remember and apply customer communication preferences for ongoing correspondence?","action":"Record customer communication preferences (format, channel, font size) in your CRM or customer database and apply them automatically to ongoing correspondence. Flag preferences so all staff can see and follow them.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.7-DD-3b","questionText":"Do staff who create documents know how to use heading styles, alt text, and proper structure?","action":"Create accessible document templates with built-in heading styles, alt text prompts, and correct table structure. Add an accessibility checklist to your document review process.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.7-DD-6a","questionText":"What is your process for handling alternative format requests?","action":"Document a process for alternative format requests: who receives the request, turnaround time targets (48 hours for large print, 5 days for Easy Read, 10 days for Braille), approved suppliers, and how to track and fulfil requests.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Are your emails designed for accessibility (readable without images, proper headings, plain text option)?","Which types of written communications have you reviewed for accessibility?","Which document types do you currently create accessibly?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverbend-summer-festival','4.4','4.4','completed','mixed','{"doingWell":["Do your emergency procedures include plans for people with disabilities?","Are there visual and audible alarms for emergencies?","Do you have evacuation equipment such as evacuation chairs?"],"priorityActions":[{"questionId":"4.4-1-2","questionText":"Are emergency exits accessible to people with mobility aids?","action":"Audit all emergency exits for step-free access, adequate door width (minimum 850mm per AS 1428.1), and clear approach paths for wheelchair and mobility aid users.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"4.4-1-4","questionText":"Do staff know how to assist customers with different needs during an evacuation?","action":"Conduct disability-inclusive evacuation training for all staff, covering wheelchair assistance, guiding a person who is blind, communicating with Deaf people, and supporting people experiencing anxiety or confusion.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true}],"areasToExplore":["Do you have Personal Emergency Evacuation Plans (PEEPs) for people who need them?","How do you communicate with Deaf visitors during an emergency?","Are emergency procedures displayed in accessible formats?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverbend-summer-festival','4.5','4.5','completed','needs-work','{"doingWell":["Do you have a way for customers to provide feedback about accessibility?","Have you received and responded to accessibility-related reviews?","Do you track accessibility feedback to identify patterns?"],"priorityActions":[{"questionId":"4.5-F-2","questionText":"Are your surveys and feedback forms accessible?","action":"Audit your surveys and feedback forms for WCAG 2.2 AA compliance. Ensure they are keyboard navigable, screen reader compatible, have clear labels, provide adequate time, and are available in alternative formats (phone, paper, Easy Read).","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.5-F-3","questionText":"Do you actively monitor and respond to online reviews?","action":"Set up monitoring for accessibility-related mentions in Google Reviews, TripAdvisor, social media, and industry platforms. Respond to accessibility concerns promptly and publicly, showing you take them seriously and are acting on them.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.5-F-4","questionText":"Do you regularly review and act on accessibility feedback?","action":"Establish a regular review cycle (at least quarterly) for accessibility feedback. Assign responsibility for reviewing, categorising, prioritising, and acting on feedback. Report back to customers on changes made.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.5-D-6","questionText":"Is there an escalation process for serious accessibility complaints?","action":"Document an escalation process for serious accessibility complaints. Define what constitutes a serious complaint (safety risk, discrimination allegation, repeated issue), who it escalates to, and the expected resolution timeframe.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do you offer multiple ways for customers to provide feedback?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverbend-summer-festival','6.1','6.1','completed','mixed','{"doingWell":["Does your event promotion include accessibility information?","Can attendees request accessibility accommodations during registration?","Have people with disability been consulted in planning this event?"],"priorityActions":[{"questionId":"6.1-PC-1","questionText":"Has accessibility been considered in the early planning stages of this event?","action":"Integrate accessibility into your event planning checklist from the earliest concept stage. Retrofitting accommodations is costlier and less effective than designing them in.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"6.1-D-1","questionText":"Have you set an accessibility budget for this event?","action":"Allocate a specific accessibility budget line item for your event. Include Auslan interpreters, captioning, hearing augmentation, accessible materials, equipment hire, and contingency for on-the-day requests. A typical allocation is 5-15% of overall event budget.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"6.1-D-5","questionText":"What is the deadline for accessibility accommodation requests?","action":"Set a clear deadline for accommodation requests (typically 2-4 weeks before the event) and communicate it prominently. Also establish a process for handling late or on-the-day requests, as some needs cannot be anticipated in advance.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["What information is provided in your event accessibility statement?","Are your promotional materials available in accessible formats?","Do procurement contracts require suppliers and vendors to meet accessibility standards?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverbend-summer-festival','6.3','6.3','completed','mixed','{"doingWell":["Is there clear, accessible wayfinding signage at the event?","Is there an information/help desk at the event?","Does signage include QR codes linking to accessible digital information?"],"priorityActions":[{"questionId":"6.3-D-4","questionText":"Are social stories or visual narratives available?","action":"Develop social stories or visual narratives for the event, particularly useful for autistic attendees and people with intellectual disability. Include what to expect on arrival, what the event looks like, where to go for help, and what happens at key moments. Publish them on the event website at least two weeks beforehand.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"6.3-D-8","questionText":"Is a digital navigation or wayfinding app available for the event?","action":"Consider providing a digital wayfinding or navigation app for the event. It should be accessible (screen-reader compatible, high contrast), include accessible routes, and show key facilities. For large events, this significantly improves independence and reduces anxiety.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"6.3-D-9","questionText":"Are speakers and presenters briefed on accessible presentation practices?","action":"Brief all speakers and presenters on accessible presentation practices: describe visual content verbally, face the audience (for lip-readers), use plain language, pause for interpreters, provide slides in advance for captioners, and use high-contrast slide design. Circulate a written accessibility guide as part of speaker onboarding.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"6.3-D-10","questionText":"Are event communications written in plain language?","action":"Write all event communications in plain language: short sentences, common words, active voice, clear structure, and avoid jargon. Test key documents with the Hemingway Editor or similar readability tool (aim for Grade 8 reading level). This benefits all attendees, not just those with disability.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Is event information available in accessible formats?","How will announcements be communicated accessibly?","Are tactile wayfinding elements provided?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverbend-summer-festival','7.1','7.1','completed','mixed','{"doingWell":["Does your central accessibility information register cover every venue accurately and stay updated?","Do all venues in your event meet a documented minimum accessibility standard?","Do you brief venue managers on event-specific accessibility expectations?"],"priorityActions":[{"questionId":"7.1-PC-2","questionText":"Is there a single named owner accountable for accessibility across all venues?","action":"Name a senior role as precinct-wide accessibility owner. Give them documented authority, budget, and direct reporting to the Event Director.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"7.1-DD-1","questionText":"Do you pre-audit each venue against your minimum standard before contracting?","action":"Introduce pre-audit for at least main-stage and high-traffic venues. Use an accessibility consultant or trained internal auditor.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"7.1-DD-8","questionText":"Do you use real-time access status updates (lift outage, accessible toilet closure) across the precinct?","action":"Document a real-time update process. Define the trigger, pre-write templates, and assign a single channel owner.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"7.1-DD-9","questionText":"Do you measure and compare accessibility metrics venue-by-venue?","action":"Introduce basic venue-level accessibility metrics. Even just complaint count and satisfaction score per venue is a start.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Is wayfinding consistent and accessible from HUB to satellite venues?","Do you provide an accessible event-wide map (digital and print)?","Is there a venue-by-venue access summary published in your program?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;

  -- ===== Town Hall & Civic Centre =====
  select id into v_site from sites where organisation_id = v_org and name = 'Town Hall & Civic Centre';
  values ('seed-redgum-town-hall-civic-centre','1.1','1.1','completed','mixed','{"doingWell":["Do you have accessibility information available for customers before they visit?","Where would it be easiest to start sharing accessibility information?","Where is your accessibility information published?"],"priorityActions":[{"questionId":"1.1-D-1b","questionText":"How easy is it to find your accessibility information from your homepage?","action":"Make your accessibility information findable within two clicks from your homepage. Add a prominent link in your main navigation, footer, or header. Avoid burying it under generic headings.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["What''s currently a barrier for you to share accessibility information?","What types of accessibility information do you currently share?","Does your physical access information include specific details that help customers plan?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','2.1','2.1','completed','mixed','{"doingWell":["Do you have designated accessible parking spaces?","Is the drop-off zone level and easy to access from the footpath?","Is the path from accessible parking to the entrance smooth and level?"],"priorityActions":[{"questionId":"2.1-F-2","questionText":"Are accessible parking spaces located close to the main entrance?","action":"Relocate or designate accessible parking spaces as close as practicable to the main entrance. AS/NZS 2890.6 recommends the shortest practicable route. Prioritise spaces nearest to the accessible entry path.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-6b","questionText":"If the accessible route differs from the main pedestrian path, is it clearly signed?","action":"Install clear signage at the point where the accessible route diverges from the main pedestrian path. Use the ISA with directional arrows and ensure signs are visible from both directions. Include distance or travel time where helpful.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.1-F-8","questionText":"Is the parking area itself well-lit?","action":"Improve lighting across the parking area, with particular focus on accessible bays, the path to the entrance, and any changes in level. Aim for uniform illumination of at least 40 lux at ground level in accordance with AS/NZS 1158.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.1-D-13","questionText":"Are accessible parking spaces clearly marked with both ground markings and vertical signage?","action":"Mark accessible parking spaces with both ground-level ISA symbols (painted on the bay surface) and vertical signage (a sign post or wall-mounted sign at min 1200mm height). Both are required under AS/NZS 2890.6 Cl 2.4.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Is there a drop-off zone near the entrance for customers who need it?","Is there directional signage on the road approach directing visitors to accessible parking?","Do staff know how to direct customers to accessible parking and entry points?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','2.2','2.2','completed','mixed','{"doingWell":["What does your main entrance have? (select all that apply)","If there are stairs or steps at the entrance, do they have handrails or grab rails on both sides?","Do the stair or step edges have contrasting nosing strips so each step is clearly visible?"],"priorityActions":[{"questionId":"2.2-D-26","questionText":"Are there tactile ground surface indicators (TGSIs) at the top and bottom of the stairs or steps?","action":"Install tactile ground surface indicators (TGSIs) at the top and bottom of entrance stairs. Warning TGSIs (truncated domes) must extend 600mm from the stair nosing across the full width, with min 30% luminance contrast, per AS 1428.4.1.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.2-D-27","questionText":"If there is a ramp, does it have handrails on both sides?","action":"Install handrails on both sides of the entrance ramp. Handrails must be continuous, 865-1000mm above the ramp surface, extend 300mm beyond the top and bottom, and have a graspable profile of 30-50mm diameter per AS 1428.1 Cl 10.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.2-D-28","questionText":"Does the ramp feel too steep for someone using a wheelchair or walking frame?","action":"Regrade or rebuild the ramp to comply with AS 1428.1 Cl 10: max gradient 1:14 for ramps up to 9m, 1:8 for kerb ramps. Provide level landings (min 1200mm long) at the top, bottom, and at max 9m intervals. Consider 1:20 or gentler for best practice.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.2-D-29","questionText":"Are there tactile ground surface indicators (TGSIs) at the top and bottom of the ramp?","action":"Install warning TGSIs (truncated domes) at the top and bottom of the entrance ramp per AS 1428.4.1. TGSIs must extend 600mm from the ramp edge across the full width, with min 30% luminance contrast against the surrounding surface.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','3.1','3.1','completed','mixed','{"doingWell":["Which of these seating options does your venue currently offer?","Is there space for wheelchair users alongside seated companions?","Are tables and counters at accessible heights for wheelchair users?"],"priorityActions":[{"questionId":"3.1-1-4","questionText":"Can furniture be rearranged to accommodate different needs?","action":"Replace or supplement fixed furniture with movable options so staff can rearrange layouts for wheelchair users, mobility aid users, or service animals.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.1-D-9","questionText":"Are controls within the space (light switches, power outlets, thermostats) accessible?","action":"Relocate or supplement controls (light switches, outlets, thermostats) to be between 900-1100mm from the floor, operable with one hand, and reachable from a seated position without tight grasping or twisting, per AS 1428.1:2021 Clause 16.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.1-D-10","questionText":"Is there an accessible writing surface available where customers need to complete forms or paperwork?","action":"Provide an accessible writing surface at locations where forms or paperwork are completed. Include a table or counter at 750-830mm height with minimum 800mm knee clearance and clear floor space for a wheelchair.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Is there a variety of seating options (with arms, without arms, different heights)?","Which types of accessible seating does your venue offer in fixed seating areas?","In fixed seating areas, do wheelchair spaces provide equivalent sightlines to other patrons?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','4.2','4.2','completed','strong','{"doingWell":["Have staff received disability awareness or inclusion training?","Do staff feel confident communicating with customers who have different needs?","Do you have a process for customers to request assistance before arriving?"],"priorityActions":[{"questionId":"4.2-F-2","questionText":"Do staff know how to welcome and assist customers with assistance animals?","action":"Train all staff on assistance animal rights under the Disability Discrimination Act 1992. Staff must know they cannot refuse entry, request proof of disability, or charge extra for assistance animals.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"4.2-F-6","questionText":"Do staff know where accessible facilities are located to direct customers?","action":"Ensure all staff know the location of accessible toilets, lifts, hearing loops, quiet spaces, accessible parking, and any other accessible facilities. Include this in onboarding and display a staff reference map.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Is there a clear process for handling accessibility complaints or feedback?","Do staff know how to assist customers during an emergency evacuation?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','5.1','5.1','completed','mixed','{"doingWell":["Do you have a documented accessibility or disability inclusion policy?","Do you have a Disability Inclusion Action Plan (DIAP) or equivalent?","Do you accept the Companion Card for carers or support people?"],"priorityActions":[{"questionId":"5.1-F-6","questionText":"Does your organisation have a policy on assistance animals?","action":"Establish a formal assistance animal policy immediately. Under the DDA 1992 and state legislation, refusing entry to an assistance animal is unlawful. Train all staff on their obligations, including recognising different types of accreditation.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"5.1-D-8","questionText":"Do you track and report on accessibility improvements?","action":"Implement a system to track accessibility improvements over time. Record what changes have been made, when, and their impact. Report progress to leadership at least quarterly to maintain momentum and accountability.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.1-D-9","questionText":"Is there a senior leader or executive sponsor responsible for accessibility?","action":"Appoint a senior leader as executive sponsor for accessibility. This role should have authority to allocate resources, champion accessibility at board level, and hold teams accountable for delivering on inclusion commitments.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do you maintain a single, named accessibility information register that all customer-facing channels reference?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','5.3','5.3','completed','strong','{"doingWell":["Do all customer-facing staff receive disability awareness training?","Is disability awareness included in staff onboarding?","Is disability training refreshed regularly?"],"priorityActions":[{"questionId":"5.3-F-3","questionText":"Do staff know how to use accessibility features and equipment?","action":"Ensure all relevant staff can operate the accessibility features and equipment at your venue. Create a quick-reference guide covering each item, its location, and basic operation steps.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.3-D-8","questionText":"Do staff know who to contact if they need advice on accessibility?","action":"Designate and publicise a clear point of contact for accessibility advice. Staff need to know who to call when they encounter an unfamiliar situation. This could be an accessibility champion, a dedicated role, or an external advisory service.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Does training cover common assistive technologies that customers may use?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','5.5','5.5','completed','strong','{"doingWell":["Do you regularly review your accessibility performance?","Do you set accessibility improvement goals?","Do you track accessibility-related metrics or KPIs?"],"priorityActions":[{"questionId":"5.5-D-13","questionText":"Do you share accessibility learnings and best practices with your industry or sector?","action":"Share your accessibility learnings and best practices with your industry or sector. Present at conferences, publish case studies, participate in industry accessibility working groups, or contribute to sector-specific accessibility guidelines.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do you report on accessibility progress to leadership or stakeholders?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','4.4','4.4','completed','mixed','{"doingWell":["Do your emergency procedures include plans for people with disabilities?","Are emergency exits accessible to people with mobility aids?","Are there visual and audible alarms for emergencies?"],"priorityActions":[],"areasToExplore":["How do you communicate with Deaf visitors during an emergency?","Are emergency procedures displayed in accessible formats?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','4.5','4.5','completed','strong','{"doingWell":["Do you have a way for customers to provide feedback about accessibility?","Do you actively monitor and respond to online reviews?","Do you regularly review and act on accessibility feedback?"],"priorityActions":[{"questionId":"4.5-F-2","questionText":"Are your surveys and feedback forms accessible?","action":"Audit your surveys and feedback forms for WCAG 2.2 AA compliance. Ensure they are keyboard navigable, screen reader compatible, have clear labels, provide adequate time, and are available in alternative formats (phone, paper, Easy Read).","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.5-D-7","questionText":"Can customers provide feedback anonymously if they prefer?","action":"Offer at least one anonymous feedback channel. Options include an anonymous online form, a physical suggestion box, or a third-party feedback service. Ensure customers know the option exists.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.5-D-8","questionText":"Do you involve people with disabilities in reviewing or improving your services (e.g., advisory panel, co-design sessions, paid consultants)?","action":"Engage people with disabilities in reviewing and improving your services. Options include a paid advisory panel, co-design workshops, or commissioned reviews by disability consultants with lived experience. Ensure participants are compensated.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','4.6','4.6','completed','mixed','{"doingWell":["Are your marketing emails and newsletters accessible?","Can customers easily manage their communication preferences?","Is your loyalty or rewards program accessible?"],"priorityActions":[{"questionId":"4.6-F-3","questionText":"Are your promotional offers and discounts accessible to everyone?","action":"Ensure promotional offers and discounts are accessible: not communicated only through images, available in text format, redeemable through accessible channels, and with clear terms in plain language. Avoid time-limited offers that disadvantage people who need more time.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.6-D-1","questionText":"Do you offer SMS or text alternatives to email communications?","action":"Offer SMS or text message alternatives to email for key communications: appointment reminders, booking confirmations, service updates, and promotional offers. Allow customers to opt in to SMS as their preferred channel.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.6-D-7","questionText":"Do you notify customers when you make accessibility improvements?","action":"Communicate accessibility improvements to customers: update your website, send targeted notifications to customers who previously flagged related needs, post on social media, and include in newsletters.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.6-D-8","questionText":"Do your app push notifications (if applicable) work with assistive technology?","action":"Test your app push notifications with VoiceOver (iOS) and TalkBack (Android). Ensure notifications are announced by screen readers, contain meaningful text (not just a title), and link to accessible content within the app.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["If you offer live chat or online messaging, is it accessible?","Do you include Auslan (Australian Sign Language) content in any of your communications?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','5.4','5.4','completed','strong','{"doingWell":["Do you ask suppliers about their accessibility practices?","Do you prioritise suppliers with strong accessibility practices?","Do you verify that delivered products and services meet accessibility requirements?"],"priorityActions":[],"areasToExplore":["Do you consider accessibility when selecting suppliers and partners?","Do you include accessibility requirements in contracts and tenders?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','5.6','5.6','completed','mixed','{"doingWell":["Do you set and communicate accessibility standards that third-party service providers must meet when operating at your venue or on your behalf?","Have you assessed whether third-party digital platforms (apps, payment systems, self-service kiosks) meet WCAG 2.1 Level AA guidelines?","Do you review third-party accessibility performance as part of contract renewals or vendor assessments?"],"priorityActions":[{"questionId":"5.6-PC-2","questionText":"Are third-party booking or ticketing platforms you use accessible to customers with disability?","action":"Test all third-party booking platforms for accessibility (screen reader, keyboard). Request VPATs from providers. Offer alternative booking methods (phone, email) for customers who cannot use the platform.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.6-PC-3","questionText":"Do delivery or service partners maintain accessibility standards when operating on your behalf?","action":"Brief all delivery and service partners on your accessibility standards. Include accessibility in SLAs and specify accessible delivery locations and service expectations.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.6-PC-4","questionText":"Do you verify that outsourced customer-facing services (catering, security, cleaning, event staffing) are delivered accessibly?","action":"Include disability awareness in all vendor briefings and induction packs. Observe third-party interactions, collect customer feedback on their service, and raise accessibility in vendor reviews.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.6-D-3","questionText":"Do you provide accessibility briefings or induction materials to contractors, temporary staff, or event vendors working at your venue?","action":"Create an accessibility induction sheet for all contractors, temporary staff, and event vendors. Include it in your standard site induction alongside safety procedures.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["When customers interact with a third party on your premises, is the experience consistent with your own accessibility standards?","Do your procurement criteria include specific accessibility standards or certifications for suppliers?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','5.7','5.7','completed','mixed','{"doingWell":["Do your job descriptions separate inherent requirements (what the role must do) from nice-to-haves (preferred but not essential)?","Do your job ads use plain language and disclose the salary range?","Do your job ads include a clear access statement inviting candidates to request adjustments, with a named contact?"],"priorityActions":[{"questionId":"5.7-DD-4","questionText":"Do you use CV-blind or name-blind shortlisting for at least some roles?","action":"Pilot blind shortlisting on 2-3 high-volume roles. Measure shortlist diversity change.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.7-DD-9","questionText":"Do you have formal pipeline partnerships (traineeships, paid internships, graduate programs) with disability-led or sector-specific organisations?","action":"Identify one partner. Scope a small pilot (2-3 placements). Measure and scale.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do you represent disability positively in your employer branding (careers page, photos, testimonials)?","Is there a named owner or governance group responsible for signing off on inherent requirements before a role is advertised?","Are roles routinely considered for part-time, job-share, or flexible arrangements before being advertised as full-time only?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','5.8','5.8','completed','mixed','{"doingWell":["Do you offer candidates a choice of interview format (in person, video, phone, written)?","Have you confirmed interview venue access (entry, lift, accessible toilet, parking) before inviting candidates?","Are interview panels trained in disability-confident interviewing and lawful questioning?"],"priorityActions":[{"questionId":"5.8-DD-3","questionText":"Are candidates offered break flexibility (pause, extended time, multi-session interviews) during interviews or assessments?","action":"Add break offer to the interview open. Train panels to honour mid-interview pauses.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.8-DD-4","questionText":"Are psychometric, cognitive, or technical assessment tools audited for disability bias before use?","action":"Audit your current assessments. Replace or supplement the worst offenders.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.8-DD-9","questionText":"Is there a clear complaints or review mechanism specific to selection decisions, with a defined escalation path?","action":"Establish a named candidate complaints contact. Include in every rejection communication.","priority":"medium","timeframe":"30-90 days","complianceLevel":"dda-compliant"}],"areasToExplore":["Do you send interview questions to candidates in advance as a default, not only on request?","Do you use structured scoring rubrics with defined behavioural anchors (not just \"1-5 gut feel\") for every interview question?","Are candidates able to bring a support person, interpreter, or advocate to interviews if they choose?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','5.9','5.9','completed','mixed','{"doingWell":["Are managers aware of and actively using JobAccess Employment Assistance Fund (EAF) for funded workplace modifications?","Is your onboarding content (documents, videos, induction sessions) available in accessible formats by default?","Do managers receive training on supporting employees with disability, including how to have adjustment conversations?"],"priorityActions":[{"questionId":"5.9-DD-1","questionText":"Is there a named Workplace Adjustment Champion or coordinator who owns the adjustment process across the organisation?","action":"Designate an adjustment coordinator. Allocate time and budget. Publish the role.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.9-DD-4","questionText":"Are 30, 60, and 90-day check-ins structured to explicitly review adjustments, workload, and inclusion experience — not only performance?","action":"Design a structured 30/60/90 template with explicit adjustment prompts.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.9-DD-6","questionText":"Do first-time managers receive targeted training on supporting employees with disability before (or at) the point of first managing someone with a disclosed disability?","action":"Build a targeted module for first-time managers. Mandate before first disclosed report.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do you proactively offer a workplace adjustment conversation to every new hire in their first two weeks?","Do you use a workplace adjustment passport that travels with employees across role changes?","Do new hires get a personalised induction plan that explicitly covers their adjustment needs and communication preferences?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-town-hall-civic-centre','5.10','5.10','completed','mixed','{"doingWell":["Do you collect and review disclosure and retention data for employees with disability?","Are disabled employees represented at senior levels, and do you track promotion rates by disclosure status?","Do you co-design policies and practices affecting disabled staff with disabled staff themselves (not just consulted after the fact)?"],"priorityActions":[{"questionId":"5.10-PC-4","questionText":"Do you ask departing staff about disability inclusion experience in exit interviews, and do you act on what you hear?","action":"Add disability-specific prompts to exit interviews. Build an annual review cycle.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.10-DD-1","questionText":"Is meeting culture deliberately designed for inclusion (agendas in advance, recording option, captions, break pacing, clear speaking order)?","action":"Publish meeting inclusion norms. Workshop with leadership.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"5.10-DD-10","questionText":"Do you support chronic illness and mental health with flexible arrangements that go beyond statutory minimums (e.g. flexible sick leave banking, recovery leave, flexible start/end times for medication cycles)?","action":"Audit current leave policies for chronic illness fit. Draft additions.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Do you have an Employee Resource Group (ERG) or equivalent for staff with disability, and is it resourced (time, budget, exec sponsor)?","Is disability inclusion included in your annual culture/engagement survey and reported on?","Are development opportunities (conferences, training, stretch projects, mentoring) proactively offered to disabled staff — not only accessed on request?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;

  -- ===== Riverside Theatre =====
  select id into v_site from sites where organisation_id = v_org and name = 'Riverside Theatre';
  values ('seed-redgum-riverside-theatre','1.1','1.1','completed','strong','{"doingWell":["Do you have accessibility information available for customers before they visit?","What''s currently a barrier for you to share accessibility information?","Where would it be easiest to start sharing accessibility information?"],"priorityActions":[{"questionId":"1.1-F-6","questionText":"Do staff know how to confidently respond to accessibility enquiries?","action":"Prepare a reference guide of common accessibility enquiries and accurate answers so staff can respond confidently. Include details like accessible parking location, entrance type, available supports, and who to escalate to when unsure.","priority":"high","timeframe":"30-90 days"}],"areasToExplore":["Who is responsible for maintaining your accessibility information?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverside-theatre','1.3','1.3','completed','strong','{"doingWell":["Are customers invited to share their accessibility requirements during the booking or enquiry process?","Can customers explain their accessibility needs in their own words?","Is the accessibility field available on all booking paths?"],"priorityActions":[{"questionId":"1.3-PC-3","questionText":"If a customer shares accessibility requirements, is there a process to follow up before their visit?","action":"Establish a process to follow up with customers who share accessibility requirements before their visit. Confirm arrangements, provide relevant information, and ask if anything else is needed. This prevents issues on arrival.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.3-DD-5c","questionText":"Is booking information available in plain language or Easy Read format?","action":"Provide booking information in plain language, and consider creating an Easy Read version for customers with intellectual or cognitive disabilities. Use short sentences, common words, and supporting images.","priority":"medium","timeframe":"30-90 days"},{"questionId":"1.3-DD-1c","questionText":"Are time limits in the booking process generous or adjustable?","action":"Extend time limits in your booking process or provide a mechanism for users to request more time, as required by WCAG 2.2 Success Criterion 2.2.1 (Timing Adjustable). Users must be warned before timeout and given at least 20 seconds to extend.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"1.3-DD-3d","questionText":"Is the booking confirmation accessible?","action":"Ensure your booking confirmation emails and pages are accessible. Use semantic HTML, sufficient colour contrast, and plain language. Include accessibility arrangements in the confirmation details.","priority":"medium","timeframe":"30-90 days"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverside-theatre','2.1','2.1','completed','strong','{"doingWell":["Do you have designated accessible parking spaces?","Are accessible parking spaces located close to the main entrance?","Is there a drop-off zone near the entrance for customers who need it?"],"priorityActions":[{"questionId":"2.1-D-12b","questionText":"Are there kerb ramps or dropped kerbs where the path crosses vehicle areas or changes level?","action":"Install kerb ramps or dropped kerbs at every point where the accessible path crosses a vehicle area or encounters a level change. Ramps must have a maximum gradient of 1:8, tactile ground surface indicators at the base, and a slip-resistant surface per AS 1428.1 Cl 10.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"2.1-D-16","questionText":"Is the walking route from parking to the entrance safely lit, with readable signage after dark?","action":"Install or upgrade lighting along the walking route from parking to the entrance so that surfaces and signage are clearly visible after dark. Ensure wayfinding signs are illuminated or retroreflective. Target at least 40 lux at ground level per AS/NZS 1158.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverside-theatre','2.2','2.2','completed','strong','{"doingWell":["What does your main entrance have? (select all that apply)","If there are stairs or steps at the entrance, do they have handrails or grab rails on both sides?","Do the stair or step edges have contrasting nosing strips so each step is clearly visible?"],"priorityActions":[{"questionId":"2.2-D-25","questionText":"Are the stair or step risers enclosed (no open gaps between steps)?","action":"Enclose all open risers on entrance stairs. Open risers create a catch hazard for cane tips, prosthetic feet, and shoe toes. Install riser panels or replace the staircase with a compliant design per AS 1428.1 Cl 11.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.2-D-18","questionText":"Are entrance mats and surface changes flush and secure?","action":"Secure all entrance mats flush with the surrounding floor surface (max 3mm lip). Replace any mats that curl at edges, have thick pile that impedes wheels, or sit in a recessed frame with raised edges. Ensure surface changes do not create trip hazards.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"2.2-F-6","questionText":"Do staff know how to assist customers who need support entering the building?","action":"Train customer-facing staff on how to assist visitors who may need support entering the building. Cover door holding, guiding someone with vision impairment, wheelchair etiquette (always ask first), and the location of the accessible entrance and alternative routes.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverside-theatre','2.3','2.3','completed','strong','{"doingWell":["Are main circulation paths at least 1 metre wide?","Are paths kept clear of obstacles and trip hazards (e.g., bins, plant pots, or furniture)?","Does your venue have any internal level changes? Select all that apply:"],"priorityActions":[{"questionId":"2.3-D-26","questionText":"Do internal stair edges have contrasting nosing strips so each step is clearly visible?","action":"Apply contrasting nosing strips to every step edge on internal stairs. Strips must provide min 30% luminance contrast with both the tread and riser, extend the full width, and be 50-75mm on the tread and 30mm on the riser per AS 1428.1 Cl 11.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true}],"areasToExplore":["Are internal doors easy to open for people with limited hand strength or dexterity?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverside-theatre','2.4','2.4','completed','strong','{"doingWell":["Is there seating available in queue areas for people who cannot stand for long?","Can customers request priority access when needed?","Is there a streamlined or dedicated accessible entry option that bypasses the main queue?"],"priorityActions":[{"questionId":"2.4-D-7","questionText":"Do you communicate expected wait times to customers?","action":"Implement a system to communicate expected wait times to customers. Options include digital displays, staff announcements, app notifications, or a simple chalkboard. Update the estimate at regular intervals. Provide the information in both visual and auditory formats.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"2.4-D-8","questionText":"During busy periods, do pathways remain accessible?","action":"Develop a crowd management plan that explicitly protects accessible pathways during peak periods. Assign staff to monitor key routes, use barriers that maintain 1000mm clear width, and never use queuing overflow to block accessible paths, ramps, or lift access.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverside-theatre','3.1','3.1','completed','strong','{"doingWell":["Is there a variety of seating options (with arms, without arms, different heights)?","Which of these seating options does your venue currently offer?","Is there space for wheelchair users alongside seated companions?"],"priorityActions":[{"questionId":"3.1-1-4","questionText":"Can furniture be rearranged to accommodate different needs?","action":"Replace or supplement fixed furniture with movable options so staff can rearrange layouts for wheelchair users, mobility aid users, or service animals.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.1-D-2","questionText":"Are aisles and pathways between furniture wide enough throughout the space?","action":"Rearrange furniture to achieve minimum 1000mm clear width between obstacles, with 1200mm preferred and 1800mm at passing points, per AS 1428.1:2021 Clause 7.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.1-D-7","questionText":"Is there a designated guide dog or assistance animal relief area?","action":"Establish a designated assistance animal relief area with appropriate surface, drainage, waste disposal, and clear signage. Locate it within reasonable distance of main areas and communicate its location to visitors.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverside-theatre','3.2','3.2','completed','strong','{"doingWell":["Do you have at least one accessible toilet?","Do you know where the nearest accessible toilet is?","Is toilet signage clear, with tactile and Braille elements where required?"],"priorityActions":[{"questionId":"3.2-D-1","questionText":"Are toilet doors easy to open and lock from inside?","action":"Replace toilet door hardware with lever handles or D-pulls operable with one hand. Ensure the lock is a sliding bolt type easy to operate without fine motor skills. The accessible toilet door must open outward or slide, and provide minimum 850mm clear opening width per AS 1428.1:2021 Clause 19.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.2-D-4","questionText":"Are taps lever-type, sensor-operated, or otherwise usable without gripping or twisting?","action":"Replace all taps in accessible facilities with lever-type, sensor-operated, or push-type taps that can be operated without gripping or twisting, per AS 1428.1:2021 Clause 19.5. Set sensor taps to stay on for at least 10 seconds.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"}],"areasToExplore":["Is there a mirror that can be used from both standing and seated positions?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverside-theatre','3.3','3.3','completed','strong','{"doingWell":["Does lighting support comfortable navigation and sensory regulation?","Are there quiet or reset spaces available for people who need a sensory break?","Is background noise at a level that allows conversation?"],"priorityActions":[{"questionId":"3.3-1-4","questionText":"Are there any flashing lights or sudden loud noises that could affect some visitors?","action":"Audit the venue for any flashing lights (strobe effects, digital signage, emergency beacons) and sudden loud noises, then eliminate them or provide advance warnings per WCAG 2.2 SC 2.3.1 (three flashes threshold).","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory","safetyRelated":true},{"questionId":"3.3-1-6","questionText":"Are sensory kits or supports available for customers and visitors?","action":"Create sensory support kits (noise-reducing headphones, fidget tools, sunglasses, communication cards) available for loan at reception or entry points.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"3.3-D-2","questionText":"Is lighting even and consistent at key service and communication areas (reception, counters, information points)?","action":"Improve lighting at service counters, reception, and information points to a minimum 300 lux evenly distributed, avoiding shadows on faces. Good lighting at these points is essential for lipreading and clear communication.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverside-theatre','3.7','3.7','completed','strong','{"doingWell":["Do you have key information available in alternative formats on-site (large print, Easy Read, audio)?","Can customers access information digitally during their visit (QR codes, app, website)?","Do you provide tactile information for people who are blind or have low vision (tactile signs, Braille, tactile maps)?"],"priorityActions":[{"questionId":"3.7-DD-6b","questionText":"Are hearing loops regularly tested and maintained?","action":"Establish a monthly testing schedule for all hearing loops. Test field strength with a loop listener or field-strength meter, check for interference from electronic equipment, and keep a maintenance log. Engage a specialist for annual calibration.","priority":"high","timeframe":"30-90 days","complianceLevel":"mandatory"},{"questionId":"3.7-DD-7b","questionText":"Do you ask about captioning needs when people register for events or book tours?","action":"Add a question about captioning or communication needs to event registration, tour booking, and group visit enquiry forms. Allow adequate lead time (minimum 2 weeks) to arrange services.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverside-theatre','3.8','3.8','completed','strong','{"doingWell":["What types of experiences or activities does your venue offer? Select all that apply:","Can activities or experiences be modified to suit different abilities?","Can customers take breaks or pauses during experiences without losing their place?"],"priorityActions":[{"questionId":"3.8-1-3","questionText":"Are participants able to go at their own pace during activities?","action":"Redesign activity scheduling to allow self-paced participation, including options to pause, repeat segments, or take breaks without disadvantage.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":["Is there step-free access to all spectator areas, including premium areas?","Can you provide accessible tables with knee clearance at various locations in meeting rooms?"],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
  on conflict (organisation_id, site_id, module_id) do nothing;
  on conflict (organisation_id, site_id, module_id, question_id) do nothing;
  values ('seed-redgum-riverside-theatre','4.1','4.1','completed','strong','{"doingWell":["Do you offer alternatives to phone calls for customers who cannot or prefer not to use voice telephone?","Are your staff trained to receive calls via the National Relay Service (NRS)?","Do non-phone enquiries (email, text, chat) receive responses within the same timeframe as phone calls?"],"priorityActions":[{"questionId":"4.1-PC-3","questionText":"Do you capture and use customer communication preferences (preferred contact method, format needs)?","action":"Add a communication preferences field to your customer records (preferred contact method, format needs such as large print or Easy Read). Ask at first contact and store for future use.","priority":"high","timeframe":"30-90 days","complianceLevel":"best-practice"},{"questionId":"4.1-PC-7","questionText":"Is there a quiet space available for communication with customers who need a calmer environment?","action":"Designate a quiet, low-stimulus space where staff can have conversations with customers who need a calmer environment. This could be a private office, meeting room, or screened area.","priority":"medium","timeframe":"30-90 days","complianceLevel":"best-practice"}],"areasToExplore":[],"professionalReview":[]}'::jsonb,now() - interval '6 days',now() - interval '4 days',v_org,v_site,v_user,v_user)
